WITH payload AS (
  SELECT $RISQQ71${"questions":[{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.10","internal_question_no":"07D.010","question_sort_key":7401000.185,"question_text":"Are all access points to the machinery space and fuel preparation room adequately protected from exposure to hazardous and toxic areas?","guide_to_inspection":"Engine room openings are not to open into other enclosed spaces. When applying this requirement, at least the following (1) and\n(2) are to be satisfied.\n(1) Elevator trunks connected to accommodation spaces are not to be installed.\n(2) Engine room escape trunks are provided with double doors.\n(Guidelines for Ships using Ammonia as Fuel, 2024).\nWhen fuel preparation rooms cannot be located on open deck, or accessed from open deck, access should be provided through\nan airlock.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)\nAirlock Room Requirements and Maintenance:\n> The airlock room must be a gas-tight space constructed of steel, equipped with two doors spaced a minimum of 1.5\nmeters and a maximum of 2.5 meters apart.\n> Airlock doors must be self-closing and fitted with mechanisms that prevent them from being held open.\n> The airlock space must be equipped with sensors to monitor the ingress of cargo vapours.\n> Mechanical ventilation is required, and the space must be maintained at a pressure higher than that of the surrounding\nareas.\n> Both audio and visual alarms must be installed to activate if both doors are opened simultaneously.\n> Testing and Inspection:\n> Regular testing of the airlock system is essential and should include:\n> Visual inspection of the doors and seals\n> Alarm functionality test\n> Ultrasonic leak detection test","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":106,"source_page_end":106,"raw_source_text":"Are all access points to the machinery space and fuel preparation room adequately protected from exposure\nto hazardous and toxic areas? (V)\nGuide to Inspection\nEngine room openings are not to open into other enclosed spaces. When applying this requirement, at least the following (1) and\n(2) are to be satisfied.\n(1) Elevator trunks connected to accommodation spaces are not to be installed.\n(2) Engine room escape trunks are provided with double doors.\n(Guidelines for Ships using Ammonia as Fuel, 2024).\nWhen fuel preparation rooms cannot be located on open deck, or accessed from open deck, access should be provided through\nan airlock.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)\nAirlock Room Requirements and Maintenance:\n> The airlock room must be a gas-tight space constructed of steel, equipped with two doors spaced a minimum of 1.5\nmeters and a maximum of 2.5 meters apart.\n> Airlock doors must be self-closing and fitted with mechanisms that prevent them from being held open.\n> The airlock space must be equipped with sensors to monitor the ingress of cargo vapours.\n> Mechanical ventilation is required, and the space must be maintained at a pressure higher than that of the surrounding\nareas.\n> Both audio and visual alarms must be installed to activate if both doors are opened simultaneously.\n> Testing and Inspection:\n> Regular testing of the airlock system is essential and should include:\n> Visual inspection of the doors and seals\n> Alarm functionality test\n> Ultrasonic leak detection test","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.11","internal_question_no":"07D.011","question_sort_key":7401100.186,"question_text":"Are drip trays installed in areas where ammonia leakage may occur to mitigate damage to the ship’s structure and limit the impact of potential spills?","guide_to_inspection":"5.9.1 Drip trays should be fitted where leakage may occur which can cause damage to the ship structure or where limitation of\nthe area which is affected from a spill is necessary.\n5.9.2 Drip trays should be made of suitable material.\n5.9.3 The drip tray should be thermally insulated from the ship’s structure so that the surrounding hull or deck structures are not\nexposed to unacceptable cooling, in case of leakage of liquid fuel.\n5.9.4 Each tray should be fitted with a drain valve to enable water to be drained over the ship’s side where the tray is installed in a\nlocation where water may be retained.\n5.9.5 Each tray should have a sufficient capacity to ensure that the assumed maximum amount of spill according to\nthe risk assessment can be handled.\n5.9.6 Drip trays should be provided with means to safely drain or transfer spills that contain ammonia to be\ncontained or treated.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":107,"source_page_end":107,"raw_source_text":"Are drip trays installed in areas where ammonia leakage may occur to mitigate damage to the ship’s structure\nand limit the impact of potential spills? (V)\nGuide to Inspection\n5.9.1 Drip trays should be fitted where leakage may occur which can cause damage to the ship structure or where limitation of\nthe area which is affected from a spill is necessary.\n5.9.2 Drip trays should be made of suitable material.\n5.9.3 The drip tray should be thermally insulated from the ship’s structure so that the surrounding hull or deck structures are not\nexposed to unacceptable cooling, in case of leakage of liquid fuel.\n5.9.4 Each tray should be fitted with a drain valve to enable water to be drained over the ship’s side where the tray is installed in a\nlocation where water may be retained.\n5.9.5 Each tray should have a sufficient capacity to ensure that the assumed maximum amount of spill according to\nthe risk assessment can be handled.\n5.9.6 Drip trays should be provided with means to safely drain or transfer spills that contain ammonia to be\ncontained or treated.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.12","internal_question_no":"07D.012","question_sort_key":7401200.187,"question_text":"Are the ventilation systems for air locks in good operational order, and are the audible/visual alarms function tested regularly?","guide_to_inspection":"Airlocks should be mechanically ventilated at an overpressure relative to the adjacent hazardous/toxic area or space.\n(5.11.2, MSC.1-Circ.1687).\nAn audible and visual alarm system to give a warning on both sides of the airlock should be provided to indicate if more than one\ndoor is moved from the closed position. Audible and visual alarms should be given at a manned location to indicate both loss of\npressure and opening of the airlock doors when pressure is lost.\n(5.11.5, & 5.11.6, MSC.1-Circ.1687).","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":107,"source_page_end":107,"raw_source_text":"Are the ventilation systems for air locks in good operational order, and are the audible/visual alarms function\ntested regularly? (V)\nGuide to Inspection\nAirlocks should be mechanically ventilated at an overpressure relative to the adjacent hazardous/toxic area or space.\n(5.11.2, MSC.1-Circ.1687).\nAn audible and visual alarm system to give a warning on both sides of the airlock should be provided to indicate if more than one\ndoor is moved from the closed position. Audible and visual alarms should be given at a manned location to indicate both loss of\npressure and opening of the airlock doors when pressure is lost.\n(5.11.5, & 5.11.6, MSC.1-Circ.1687).","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.13","internal_question_no":"07D.013","question_sort_key":7401300.188,"question_text":"Are continuously manned spaces located outside the machinery space, and are remote monitoring systems for critical areas and equipment within the machinery space in working condition and maintained regularly?","guide_to_inspection":"Manning and Monitoring Requirements for Engine Room Safety\nSpaces that are required to be continuously manned by ship personnel must not be located within engine rooms. Specifically,\nengine control rooms should be situated outside of engine rooms where ammoniaconsuming equipment is installed.\nRemote monitoring systems, such as CCTV, must be provided to observe conditions within the engine room. These systems\nshould be configured to monitor, at a minimum, the following equipment and areas:\n> Ammonia consumers\n> Purifier rooms\n> Boilers\n> Inert Gas Generators (IGG)\n> Incinerators\n> Other high fire-risk equipment, including associated piping routes\n(Class NK, 2024)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":107,"source_page_end":107,"raw_source_text":"Are continuously manned spaces located outside the machinery space, and are remote monitoring systems\nfor critical areas and equipment within the machinery space in working condition and maintained regularly? (V)\nGuide to Inspection\nManning and Monitoring Requirements for Engine Room Safety\nSpaces that are required to be continuously manned by ship personnel must not be located within engine rooms. Specifically,\nengine control rooms should be situated outside of engine rooms where ammoniaconsuming equipment is installed.\nRemote monitoring systems, such as CCTV, must be provided to observe conditions within the engine room. These systems\nshould be configured to monitor, at a minimum, the following equipment and areas:\n> Ammonia consumers\n> Purifier rooms\n> Boilers\n> Inert Gas Generators (IGG)\n> Incinerators\n> Other high fire-risk equipment, including associated piping routes\n(Class NK, 2024)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.14","internal_question_no":"07D.014","question_sort_key":7401400.189,"question_text":"Are the air intakes of air-conditioning systems serving accommodation spaces,service areas, and control stations equipped with internal closure mechanisms and gas detection systems, and are these systems regularly maintained and the gas detectors routinely calibrated?","guide_to_inspection":"Air intakes and exhaust vents in compartments where people are normally expected to be present, such as accommodation\nspaces, service spaces, electrical equipment rooms or control stations, shall be provided with devices to close the openings\nfrom inside the compartment.\nGas detectors are to be fitted at the air intakes of air-conditioning systems for accommodation spaces,service spaces, control\nstations, etc. These air intakes are to be automatically closed if ammonia in concentrations exceeding 25 ppm are detected. If\nall accommodation spaces are designed to be the safe havens specified in 5.11 (Protection from Toxic Areas), air conditioning\nshould be designed to transition to air recirculation when all air intakes are closed.\n(Class NK, 2024)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":107,"source_page_end":107,"raw_source_text":"Are the air intakes of air-conditioning systems serving accommodation spaces,service areas, and control\nstations equipped with internal closure mechanisms and gas detection systems, and are these systems\nregularly maintained and the gas detectors routinely calibrated? (V)\nGuide to Inspection\nAir intakes and exhaust vents in compartments where people are normally expected to be present, such as accommodation\nspaces, service spaces, electrical equipment rooms or control stations, shall be provided with devices to close the openings\nfrom inside the compartment.\nGas detectors are to be fitted at the air intakes of air-conditioning systems for accommodation spaces,service spaces, control\nstations, etc. These air intakes are to be automatically closed if ammonia in concentrations exceeding 25 ppm are detected. If\nall accommodation spaces are designed to be the safe havens specified in 5.11 (Protection from Toxic Areas), air conditioning\nshould be designed to transition to air recirculation when all air intakes are closed.\n(Class NK, 2024)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.15","internal_question_no":"07D.015","question_sort_key":7401500.19,"question_text":"Are low-temperature fuel pipes thermally insulated, and is the insulation maintained in good condition?","guide_to_inspection":"Low-temperature piping should be thermally isolated from the adjacent hull structure, where necessary, to prevent the\ntemperature of the hull from falling below the design temperature of the hull material\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)\nPipes which may contain low temperature fuel are to be thermally isolated from the adjacent hull structure to prevent the\ntemperature of the hull from falling below the design temperature of the hull\nmaterial.\nPipes, which may contain low temperature fuel, are to be thermally insulated to an extent which will minimize condensation of\nmoisture or frosting.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":108,"source_page_end":108,"raw_source_text":"Are low-temperature fuel pipes thermally insulated, and is the insulation maintained in good condition? (V)\nGuide to Inspection\nLow-temperature piping should be thermally isolated from the adjacent hull structure, where necessary, to prevent the\ntemperature of the hull from falling below the design temperature of the hull material\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)\nPipes which may contain low temperature fuel are to be thermally isolated from the adjacent hull structure to prevent the\ntemperature of the hull from falling below the design temperature of the hull\nmaterial.\nPipes, which may contain low temperature fuel, are to be thermally insulated to an extent which will minimize condensation of\nmoisture or frosting.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.16","internal_question_no":"07D.016","question_sort_key":7401600.191,"question_text":"Are the bunker manifold and its associated instrumentation, including the Emergency Shutdown (ESD) system and Emergency Release Couplers (ERC) /Emergency Release System (ERS), maintained in good condition? Are officers familiar with the operation of the ESD, ERC, and ERS systems, and are these systems regularly tested to ensure operational readiness, and are low-temperature fuel pipes thermally insulated, and is the insulation maintained in good condition?","guide_to_inspection":"8.4.1 The bunkering manifold should be designed to withstand the external loads during bunkering. The connections at the\nbunkering station should be arranged in order to achieve a dry-disconnect operation in one of the followings ways:\n1. a dry-disconnect/connect coupling;\n2. a manual connect coupler or hydraulic connect coupler, used to connect the bunker system to the receiving vessel bunkering\nmanifold presentation flange; or\n3. a bolted flange to flange assembly.\n8.4.3 An emergency release coupler (ERC)/emergency release system (ERS) or equivalent means should be provided,\nunless installed on the bunkering supply side of the bunkering line. It should enable a quick physical disconnection\n“dry break-away”of the bunker system in an emergency event.\n8.5.1 An arrangement for purging fuel bunkering lines with inert gas should be provided.\n8.5.2 The bunkering system should be so arranged that no gas is discharged to the atmosphere during filling of\nstorage tanks. Vapour return line, where fitted, should be sized adequately taking into consideration the expansion\nratio of the fuel during bunkering operations.\n8.5.3 A manually operated stop valve and a remote operated shutdown valve in series, or a combined manually\noperated and remote valve should be fitted in every bunkering line close to the connecting point. It should be possible\nto operate the remote valve in the control location for bunkering operations and/or from another safe location.\n8.5.4 A bunkering-safety link (BSL), or an equivalent means for automatic and manual ESD communication to the\nbunkering source should be fitted.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":108,"source_page_end":108,"raw_source_text":"Are the bunker manifold and its associated instrumentation, including the Emergency Shutdown (ESD)\nsystem and Emergency Release Couplers (ERC) /Emergency Release System (ERS), maintained in good condition?\nAre officers familiar with the operation of the ESD, ERC, and ERS systems, and are these systems regularly tested\nto ensure operational readiness, and are low-temperature fuel pipes thermally insulated, and is the insulation\nmaintained in good condition? (V)\nGuide to Inspection\n8.4.1 The bunkering manifold should be designed to withstand the external loads during bunkering. The connections at the\nbunkering station should be arranged in order to achieve a dry-disconnect operation in one of the followings ways:\n1. a dry-disconnect/connect coupling;\n2. a manual connect coupler or hydraulic connect coupler, used to connect the bunker system to the receiving vessel bunkering\nmanifold presentation flange; or\n3. a bolted flange to flange assembly.\n8.4.3 An emergency release coupler (ERC)/emergency release system (ERS) or equivalent means should be provided,\nunless installed on the bunkering supply side of the bunkering line. It should enable a quick physical disconnection\n“dry break-away”of the bunker system in an emergency event.\n8.5.1 An arrangement for purging fuel bunkering lines with inert gas should be provided.\n8.5.2 The bunkering system should be so arranged that no gas is discharged to the atmosphere during filling of\nstorage tanks. Vapour return line, where fitted, should be sized adequately taking into consideration the expansion\nratio of the fuel during bunkering operations.\n8.5.3 A manually operated stop valve and a remote operated shutdown valve in series, or a combined manually\noperated and remote valve should be fitted in every bunkering line close to the connecting point. It should be possible\nto operate the remote valve in the control location for bunkering operations and/or from another safe location.\n8.5.4 A bunkering-safety link (BSL), or an equivalent means for automatic and manual ESD communication to the\nbunkering source should be fitted.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.17","internal_question_no":"07D.017","question_sort_key":7401700.192,"question_text":"Is the Ammonia Release Mitigation System (ARMS) installed and maintained in good working condition, and are the Master and responsible officers familiar with its safe operation?","guide_to_inspection":"Ammonia Release Mitigation System (ARMS)\nThe Ammonia Release Mitigation System (ARMS) is designed to safely manage ammonia by either consuming, collecting, or\ndispersing it through one of the following methods:\n> Thermal oxidation or decomposition\n> Catalytic oxidation or decomposition\n> Dissolution in water\n> Dilution with air\nUnder normal operating conditions, direct release of ammonia into the atmosphere is not allowed.\nIn the event that ammonia must be released and cannot be fully contained, ARMS must reduce the ammonia concentration to\nno more than 110 ppm to ensure safety.\nARMS is also an effective system for preventing ammonia leaks during purging operations prior to bunkering.\n(Class NK 2024)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":108,"source_page_end":108,"raw_source_text":"Is the Ammonia Release Mitigation System (ARMS) installed and maintained in good working condition,\nand are the Master and responsible officers familiar with its safe operation? (V)\nGuide to Inspection\nAmmonia Release Mitigation System (ARMS)\nThe Ammonia Release Mitigation System (ARMS) is designed to safely manage ammonia by either consuming, collecting, or\ndispersing it through one of the following methods:\n> Thermal oxidation or decomposition\n> Catalytic oxidation or decomposition\n> Dissolution in water\n> Dilution with air\nUnder normal operating conditions, direct release of ammonia into the atmosphere is not allowed.\nIn the event that ammonia must be released and cannot be fully contained, ARMS must reduce the ammonia concentration to\nno more than 110 ppm to ensure safety.\nARMS is also an effective system for preventing ammonia leaks during purging operations prior to bunkering.\n(Class NK 2024)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.18","internal_question_no":"07D.018","question_sort_key":7401800.193,"question_text":"Is the fuel supply system designed with full redundancy and segregation from the fuel tanks to the fuel consumers and are the Master and Officers familiar with the actions to be taken in the event of a failure in any part of the system?","guide_to_inspection":"9.3.1 For single fuel installations, the fuel supply system should be arranged with full redundancy and segregation all the way\nfrom the fuel tanks to the fuel consumer, so that a leakage in one system does not\nlead to an unacceptable loss of power.\n9.3.2 For single fuel installations, the fuel storage should be divided between two or more tanks. The tanks should be located in\nseparate compartments.\n9.3.3 For type C tank only, one tank may be accepted if two completely separate tank connection spaces are installed for the one\ntank.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":109,"source_page_end":109,"raw_source_text":"Is the fuel supply system designed with full redundancy and segregation from the fuel tanks to the fuel consumers\nand are the Master and Officers familiar with the actions to be taken in the event of a failure in any part of the system? (V)\nGuide to Inspection\n9.3.1 For single fuel installations, the fuel supply system should be arranged with full redundancy and segregation all the way\nfrom the fuel tanks to the fuel consumer, so that a leakage in one system does not\nlead to an unacceptable loss of power.\n9.3.2 For single fuel installations, the fuel storage should be divided between two or more tanks. The tanks should be located in\nseparate compartments.\n9.3.3 For type C tank only, one tank may be accepted if two completely separate tank connection spaces are installed for the one\ntank.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.19","internal_question_no":"07D.019","question_sort_key":7401900.194,"question_text":"Are the manually and automatically operated valves on the main fuel supply and return lines in good working condition, regularly maintained, and tested in accordance with the manufacturer’s recommendations?","guide_to_inspection":"Fuel Supply and Return Line Valves\nEach main fuel supply and return line serving fuel consumers must be equipped with:\n> A manually operated stop valve, and\n> An automatically operated master fuel valve (or a combined manual/automatic valve).\n> These valves must be:\n> Installed in series on the fuel line,\n> Located outside the machinery space where the fuel consumers are housed,\n> Positioned as close as possible to the fuel heating installation, if one is fitted.\n> The master fuel valve must be connected to the safety system and should automatically shut off the fuel supply when\ntriggered.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":109,"source_page_end":109,"raw_source_text":"Are the manually and automatically operated valves on the main fuel supply and return lines in good working condition,\nregularly maintained, and tested in accordance with the manufacturer’s recommendations? (V)\nGuide to Inspection\nFuel Supply and Return Line Valves\nEach main fuel supply and return line serving fuel consumers must be equipped with:\n> A manually operated stop valve, and\n> An automatically operated master fuel valve (or a combined manual/automatic valve).\n> These valves must be:\n> Installed in series on the fuel line,\n> Located outside the machinery space where the fuel consumers are housed,\n> Positioned as close as possible to the fuel heating installation, if one is fitted.\n> The master fuel valve must be connected to the safety system and should automatically shut off the fuel supply when\ntriggered.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.20","internal_question_no":"07D.020","question_sort_key":7402000.195,"question_text":"Are fuel tanks equipped with a high liquid level alarm, an independent sensor that automatically activates a shutoff valve, and a gas detection system, all maintained in good condition, tested regularly, and supported by objective evidence of testing?","guide_to_inspection":"Each fuel tank should be fitted with a high liquid level alarm operating independently of other liquid level indicators and giving an\naudible and visual warning when activated. an additional sensor operating independently of the high liquid level alarm should\nautomatically actuate a shutoff valve in a manner that will both avoid excessive liquid pressure in the bunkering line and prevent\nthe fuel tank from becoming liquid full.\nWhere gas detection should cause shutdown in accordance with table 1, detector voting should be applied where two units\nshould detect gas to activate shutdown. A failed detector should be considered as an active detection. The number of detectors\nin each space should be considered taking into account the size, layout and ventilation of the space.\nIf the fuel supply is shut off due to activation of an automatic valve, the fuel supply should not be opened until the reason for the\ndisconnection is ascertained and the necessary precautions taken. A readily visible notice giving instruction to this effect should\nbe placed at the operating station for the shutoff valves in the fuel supply lines.\nA caution placard or signboard should be permanently fitted in the machinery space containing gasfuelled engines, stating\nthat heavy lifting, implying danger of damage to the fuel pipes, should not be done unless the fuel supply lines are free from\nammonia.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":109,"source_page_end":109,"raw_source_text":"Are fuel tanks equipped with a high liquid level alarm, an independent sensor that automatically activates a\nshutoff valve, and a gas detection system, all maintained in good condition, tested regularly, and supported by\nobjective evidence of testing? (V)\nGuide to Inspection\nEach fuel tank should be fitted with a high liquid level alarm operating independently of other liquid level indicators and giving an\naudible and visual warning when activated. an additional sensor operating independently of the high liquid level alarm should\nautomatically actuate a shutoff valve in a manner that will both avoid excessive liquid pressure in the bunkering line and prevent\nthe fuel tank from becoming liquid full.\nWhere gas detection should cause shutdown in accordance with table 1, detector voting should be applied where two units\nshould detect gas to activate shutdown. A failed detector should be considered as an active detection. The number of detectors\nin each space should be considered taking into account the size, layout and ventilation of the space.\nIf the fuel supply is shut off due to activation of an automatic valve, the fuel supply should not be opened until the reason for the\ndisconnection is ascertained and the necessary precautions taken. A readily visible notice giving instruction to this effect should\nbe placed at the operating station for the shutoff valves in the fuel supply lines.\nA caution placard or signboard should be permanently fitted in the machinery space containing gasfuelled engines, stating\nthat heavy lifting, implying danger of damage to the fuel pipes, should not be done unless the fuel supply lines are free from\nammonia.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.21","internal_question_no":"07D.021","question_sort_key":7402100.196,"question_text":"Is the emergency and safety equipment provided suitable for use with ammonia fuel and maintained in good condition?","guide_to_inspection":"20.4.3 A stretcher that is suitable for hoisting an injured person from spaces, such as tank hold spaces, should be kept in a\nreadily accessible location.\n20.4.4 The ship should have onboard medical first aid equipment, including oxygen resuscitation equipment, based on the\nrequirements of the Medical First Aid Guide (MFAG) for ammonia.\n20.4.5 Suitable respiratory and eye protection for emergency escape purposes should be provided for every person on board,\nsubject to the following:\n1. filter-type respiratory protection is unacceptable;\n2. self-contained breathing apparatus should have at least 15 minutes of service time; and\n3. emergency escape respiratory protection should not be used for fire-fighting or cargo handling purposes and should be\nmarked to that effect.\n20.5.1 Sufficient, but not less than three complete sets of safety equipment, should be provided in addition to fire-fighter’s\noutfits required by SOLAS regulation II-2/10.10. These additional sets should provide adequate personal protection to permit\nentry and work in a gas-filled space, and be equipped with two-way portable radiotelephone apparatus comprising of ear piece\nwith microphone and push-totalk units. This equipment should consider the nature of ammonia.\n20.5.2 Each complete set of safety equipment should consist of:\n1. one self-contained positive pressure air breathing apparatus incorporating full face mask not using stored oxygen and having\na capacity of at least 1,200 litres of free air. Each set should be compatible with that required by SOLAS regulation II-2/10.10;\n2. gastight protective clothing, boots and gloves to a recognized standard;\n3. steel-cored rescue line with belt; and\n4. explosion-proof lamp.\n20.5.3 An adequate supply of compressed air should be provided and should consist of:\n1. at least one fully charged spare air bottle for each breathing apparatus required by 20.5.1;\n2. an air compressor of adequate capacity capable of continuous operation, suitable for the supply of high-pressure air of\nbreathable quality; and\n3. a charging manifold capable of dealing with sufficient spare breathing apparatus air bottles for the breathing apparatus\nrequired by 20.5.1.\n20.5.4 The compressed air equipment should be inspected at least once a month by a responsible officer and the inspection\nshould be logged in the ship’s records. This equipment should also be inspected and tested by a competent person at least once\na year.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":110,"source_page_end":110,"raw_source_text":"Is the emergency and safety equipment provided suitable for use with ammonia fuel and maintained in good condition? (V)\nGuide to Inspection\n20.4.3 A stretcher that is suitable for hoisting an injured person from spaces, such as tank hold spaces, should be kept in a\nreadily accessible location.\n20.4.4 The ship should have onboard medical first aid equipment, including oxygen resuscitation equipment, based on the\nrequirements of the Medical First Aid Guide (MFAG) for ammonia.\n20.4.5 Suitable respiratory and eye protection for emergency escape purposes should be provided for every person on board,\nsubject to the following:\n1. filter-type respiratory protection is unacceptable;\n2. self-contained breathing apparatus should have at least 15 minutes of service time; and\n3. emergency escape respiratory protection should not be used for fire-fighting or cargo handling purposes and should be\nmarked to that effect.\n20.5.1 Sufficient, but not less than three complete sets of safety equipment, should be provided in addition to fire-fighter’s\noutfits required by SOLAS regulation II-2/10.10. These additional sets should provide adequate personal protection to permit\nentry and work in a gas-filled space, and be equipped with two-way portable radiotelephone apparatus comprising of ear piece\nwith microphone and push-totalk units. This equipment should consider the nature of ammonia.\n20.5.2 Each complete set of safety equipment should consist of:\n1. one self-contained positive pressure air breathing apparatus incorporating full face mask not using stored oxygen and having\na capacity of at least 1,200 litres of free air. Each set should be compatible with that required by SOLAS regulation II-2/10.10;\n2. gastight protective clothing, boots and gloves to a recognized standard;\n3. steel-cored rescue line with belt; and\n4. explosion-proof lamp.\n20.5.3 An adequate supply of compressed air should be provided and should consist of:\n1. at least one fully charged spare air bottle for each breathing apparatus required by 20.5.1;\n2. an air compressor of adequate capacity capable of continuous operation, suitable for the supply of high-pressure air of\nbreathable quality; and\n3. a charging manifold capable of dealing with sufficient spare breathing apparatus air bottles for the breathing apparatus\nrequired by 20.5.1.\n20.5.4 The compressed air equipment should be inspected at least once a month by a responsible officer and the inspection\nshould be logged in the ship’s records. This equipment should also be inspected and tested by a competent person at least once\na year.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.1","internal_question_no":"08A.001","question_sort_key":8100100.197,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":111,"source_page_end":111,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.2","internal_question_no":"08A.002","question_sort_key":8100200.198,"question_text":"Has appropriate information about the cargo and its characteristics been provided to the Master prior to loading?","guide_to_inspection":"The IMSBC Code categorises cargoes into three groups:\n> Group A —cargoes that may liquefy if shipped at a moisture content exceeding their transportable moisture limit (TML).\nTML is the maximum moisture content considered safe for carriage. Liquefaction means that the cargo becomes fluid or\nliquefies. On ships, this happens when the cargo is compacted by the ship’s motion. Cargoes that are prone to liquefaction\ncontain a certain quantity of moisture and small particles, although they may look relatively dry and granular when loaded.\nLiquefaction can lead to cargo shifting and even to the capsize of the ship.\n> Group B—cargoes that involve a chemical hazard that could give rise to a dangerous situation on a ship\n> Group C—cargoes that are neither liable to liquefy (Group A), nor involve chemical hazards (Group B), but might still be\nhazardous.\n> Cargoes can be in Group A, B or C, or Group A and B.\n> Group B cargoes are those that meet either the IMDG Code’s dangerous goods hazard criteria or the IMSBC Code’s\n‘materials hazardous only in bulk’ (MHB) criteria. MHB cargoes are materials that involve chemical hazards when\ntransported in bulk, but that do not meet the criteria for inclusion in the IMDG classes above. However, they present\nsignificant risks to health and safety when carried in bulk and require special precautions.\n> The shipper must provide the Master with valid, up-to-date information about the cargo’s physical and chemical\nproperties. The exact information and documentation they must provide is listed in the IMSBC Code under ‘Assessment of\nacceptability of consignments for safe shipment; Provision of Information’, and includes the correct Bulk Cargo Shipping\nName (cargo’s official name used in the Code) and a declaration that the cargo information is correct.\n> To carry dangerous goods in solid form in bulk, the vessel must have a Document of Compliance for the Carriage of\nDangerous Goods, supplied by the ship’s flag or classification society. The Master must have a special list, manifest or\nstowage plan identifying the cargo’s location, and there must be instructions on board for emergency response.\n(IMSBC code, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":111,"source_page_end":111,"raw_source_text":"Has appropriate information about the cargo and its characteristics been provided to the Master\nprior to loading? (V)\nGuide to Inspection\nThe IMSBC Code categorises cargoes into three groups:\n> Group A —cargoes that may liquefy if shipped at a moisture content exceeding their transportable moisture limit (TML).\nTML is the maximum moisture content considered safe for carriage. Liquefaction means that the cargo becomes fluid or\nliquefies. On ships, this happens when the cargo is compacted by the ship’s motion. Cargoes that are prone to liquefaction\ncontain a certain quantity of moisture and small particles, although they may look relatively dry and granular when loaded.\nLiquefaction can lead to cargo shifting and even to the capsize of the ship.\n> Group B—cargoes that involve a chemical hazard that could give rise to a dangerous situation on a ship\n> Group C—cargoes that are neither liable to liquefy (Group A), nor involve chemical hazards (Group B), but might still be\nhazardous.\n> Cargoes can be in Group A, B or C, or Group A and B.\n> Group B cargoes are those that meet either the IMDG Code’s dangerous goods hazard criteria or the IMSBC Code’s\n‘materials hazardous only in bulk’ (MHB) criteria. MHB cargoes are materials that involve chemical hazards when\ntransported in bulk, but that do not meet the criteria for inclusion in the IMDG classes above. However, they present\nsignificant risks to health and safety when carried in bulk and require special precautions.\n> The shipper must provide the Master with valid, up-to-date information about the cargo’s physical and chemical\nproperties. The exact information and documentation they must provide is listed in the IMSBC Code under ‘Assessment of\nacceptability of consignments for safe shipment; Provision of Information’, and includes the correct Bulk Cargo Shipping\nName (cargo’s official name used in the Code) and a declaration that the cargo information is correct.\n> To carry dangerous goods in solid form in bulk, the vessel must have a Document of Compliance for the Carriage of\nDangerous Goods, supplied by the ship’s flag or classification society. The Master must have a special list, manifest or\nstowage plan identifying the cargo’s location, and there must be instructions on board for emergency response.\n(IMSBC code, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.3","internal_question_no":"08A.003","question_sort_key":8100300.199,"question_text":"Has the Master been provided with a signed certificate or declaration, indicating the moisture content, Transportable Moisture Limit (TML), angle of repose and density, and was the cargo free of evident damage?","guide_to_inspection":"Record a Finding if the cargo was damaged for reasons other than the hatch cover’s weathertight integrity.\nBefore loading is started, copies of all appropriates certificates for the cargo shall be provided, for example moisture content,\ntransportable moisture limit (TML) and density.\nThe Master is to ensure the documents are in the correct format, can be clearly understood and gives all appropriate information\nfor the safe loading and carriage of the intended cargo.\nCertificates of transportable moisture limit must also be issued, with the interval between sample or testing and loading not\nexceeding six months. However, if it is suspected that the moisture content may have increased since the time of testing, or that\nthe flow moisture properties of the cargo may have changed –possibly resulting from heavy rainfall or inefficient stockpiling –\nadditional testing should be carried out to confirm the safety and suitability of the cargo to be loaded.\nSOLAS requires that the shippers of bulk cargoes provide the Master in writing and sufficiently in advance of loading with\ninformation on any special properties of the cargo, including the likelihood of shifting, and, for concentrates* or other cargoes\nwhich may liquefy, additional information in the form of a certificate on the moisture content of the cargo and its Transportable\nMoisture Limit (TML). Cargoes which may liquefy shall only be accepted when the actual moisture content is less than the TML.\n*Concentrates are materials obtained from a natural ore by a process of enrichment or beneficiation by physical or chemical\nseparation and removal of unwanted constituents.\nAngle of repose means the maximum slope angle of non-cohesive (i.e. free-flowing) granular material. It is measured as the\nangle between a horizontal plane and the cone slope of such material.\nCohesive material means materials other than non-cohesive materials.\nNon-cohesive material means dry materials that readily shift due to sliding during transport, as listed in Appendix 3 of the Code.\nAppendix 3 of the IMSBC Code lists a number of cargoes which are non-cohesive when dry. Each individual schedule of the\ncargoes listed in this section will state an angle of repose in the physical properties table and the trimming requirements in\nthe loading section. Cargoes not listed in this section, but exhibit properties of non-cohesive material are subject to the same\ntrimming requirements as non-cohesive cargoes.\nTo allow their safe carriage at sea, non-cohesive cargoes are required to be suitably trimmed in accordance with section 5 of the\nIMSBC Code.\nCargoes with an angle of repose less than or equal to 30° can free flow like a grain cargo. For this reason, the IMSBC Code\nrequires these cargoes to be carried in accordance with the International Grain Code in addition to the requirements of the\nIMSBC Code.\nThe angle of repose stated on the shipper’s declaration should be determined using a ‘tilting box test’. The details of this testing\nprocedure can be found in Appendix 2 of the IMSBC.\n(Articles: Looking straight at the angle of repose, 2021)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":111,"source_page_end":112,"raw_source_text":"Has the Master been provided with a signed certificate or declaration, indicating the moisture content,\nTransportable Moisture Limit (TML), angle of repose and density, and was the cargo free of evident damage?\n(V & M)\nGuide to Inspection\nRecord a Finding if the cargo was damaged for reasons other than the hatch cover’s weathertight integrity.\nBefore loading is started, copies of all appropriates certificates for the cargo shall be provided, for example moisture content,\ntransportable moisture limit (TML) and density.\nThe Master is to ensure the documents are in the correct format, can be clearly understood and gives all appropriate information\nfor the safe loading and carriage of the intended cargo.\nCertificates of transportable moisture limit must also be issued, with the interval between sample or testing and loading not\nexceeding six months. However, if it is suspected that the moisture content may have increased since the time of testing, or that\nthe flow moisture properties of the cargo may have changed –possibly resulting from heavy rainfall or inefficient stockpiling –\nadditional testing should be carried out to confirm the safety and suitability of the cargo to be loaded.\nSOLAS requires that the shippers of bulk cargoes provide the Master in writing and sufficiently in advance of loading with\ninformation on any special properties of the cargo, including the likelihood of shifting, and, for concentrates* or other cargoes\nwhich may liquefy, additional information in the form of a certificate on the moisture content of the cargo and its Transportable\nMoisture Limit (TML). Cargoes which may liquefy shall only be accepted when the actual moisture content is less than the TML.\n*Concentrates are materials obtained from a natural ore by a process of enrichment or beneficiation by physical or chemical\nseparation and removal of unwanted constituents.\nAngle of repose means the maximum slope angle of non-cohesive (i.e. free-flowing) granular material. It is measured as the\nangle between a horizontal plane and the cone slope of such material.\nCohesive material means materials other than non-cohesive materials.\nNon-cohesive material means dry materials that readily shift due to sliding during transport, as listed in Appendix 3 of the Code.\nAppendix 3 of the IMSBC Code lists a number of cargoes which are non-cohesive when dry. Each individual schedule of the\ncargoes listed in this section will state an angle of repose in the physical properties table and the trimming requirements in\nthe loading section. Cargoes not listed in this section, but exhibit properties of non-cohesive material are subject to the same\ntrimming requirements as non-cohesive cargoes.\nTo allow their safe carriage at sea, non-cohesive cargoes are required to be suitably trimmed in accordance with section 5 of the\nIMSBC Code.\nCargoes with an angle of repose less than or equal to 30° can free flow like a grain cargo. For this reason, the IMSBC Code\nrequires these cargoes to be carried in accordance with the International Grain Code in addition to the requirements of the\nIMSBC Code.\nThe angle of repose stated on the shipper’s declaration should be determined using a ‘tilting box test’. The details of this testing\nprocedure can be found in Appendix 2 of the IMSBC.\n(Articles: Looking straight at the angle of repose, 2021)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.4","internal_question_no":"08A.004","question_sort_key":8100400.2,"question_text":"Is information readily available on the ballasting and de-ballasting rate, the maximum allowable load per unit, the surface area of the tank-top plating, and the maximum allowable load per hold?","guide_to_inspection":"This information should be prominently posted or readily available to the user.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":112,"source_page_end":112,"raw_source_text":"Is information readily available on the ballasting and de-ballasting rate, the maximum allowable load\nper unit, the surface area of the tank-top plating, and the maximum allowable load per hold? (V)\nGuide to Inspection\nThis information should be prominently posted or readily available to the user.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.5","internal_question_no":"08A.005","question_sort_key":8100500.201,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":112,"source_page_end":112,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.6","internal_question_no":"08A.006","question_sort_key":8100600.202,"question_text":"Is a Class-approved loading computer or programme in use and has the operational accuracy been regularly tested?","guide_to_inspection":"A loading instrument is an instrument, which is either analogue or digital, by means of which it can be easily and quickly\nascertained that, at specified read-out points, the still water bending moments, shear forces, and the still water torsional\nmoments and lateral loads, where applicable, in any load or ballast condition will not exceed the specified permissible values. A\nloading instrument comprises hardware and software.\nSOLAS Requirement, regulation 11, Loading Instrument:\nBulk carriers of 150m in length and upwards shall be fitted with a loading instrument capable of providing information on hull\ngirder shear forces and bending moments, taking into account the recommendation adopted by the Organization.\nBulk carriers of 150m in length and upwards, constructed before 1 July 1999, shall comply with the requirements not later than\nthe date of the first intermediate or periodical survey of the ship to be carried out after 1 July 1999.\nBulk carriers of less than 150m in length, constructed on or after 1 July 2006, shall be fitted with a loading instrument capable of\nproviding information on the ship’s stability in the intact condition.\nThe computer software shall be approved for stability calculations by the Administration and shall be provided with standard\nconditions for testing purposes relating to the approved stability information.\n(SOLAS 74, 2020)\nIt is the responsibility of the ship’s Master to check the accuracy of the loading computer system at each annual survey by\napplying at least one approved test loading condition (other than light ship). If a surveyor is not present for the computer check,\na copy of the test conditions results obtained by the computer check is to be retained on board as documentation of satisfactory\ntesting for the surveyor’s verification. At each renewal survey this checking for all approved test loading conditions is to be done\nin the presence of the Society surveyor.\n(Computer Software for On-board Stability Calculations-IACS Unified Interpretations, 2017)\nRegular on-board testing should also take place and records attesting to this should be maintained.\nWhen a vessel has undergone any weight variations, such as the installation of a scrubber, a ballast water treatment plant, or\nmajor structural modifications, it is the responsibility of the vessel’s manager to ensure that the loading instrument and stability\nbooklet are updated as necessary.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":112,"source_page_end":112,"raw_source_text":"Is a Class-approved loading computer or programme in use and has the operational accuracy been\nregularly tested? (V)\nGuide to Inspection\nA loading instrument is an instrument, which is either analogue or digital, by means of which it can be easily and quickly\nascertained that, at specified read-out points, the still water bending moments, shear forces, and the still water torsional\nmoments and lateral loads, where applicable, in any load or ballast condition will not exceed the specified permissible values. A\nloading instrument comprises hardware and software.\nSOLAS Requirement, regulation 11, Loading Instrument:\nBulk carriers of 150m in length and upwards shall be fitted with a loading instrument capable of providing information on hull\ngirder shear forces and bending moments, taking into account the recommendation adopted by the Organization.\nBulk carriers of 150m in length and upwards, constructed before 1 July 1999, shall comply with the requirements not later than\nthe date of the first intermediate or periodical survey of the ship to be carried out after 1 July 1999.\nBulk carriers of less than 150m in length, constructed on or after 1 July 2006, shall be fitted with a loading instrument capable of\nproviding information on the ship’s stability in the intact condition.\nThe computer software shall be approved for stability calculations by the Administration and shall be provided with standard\nconditions for testing purposes relating to the approved stability information.\n(SOLAS 74, 2020)\nIt is the responsibility of the ship’s Master to check the accuracy of the loading computer system at each annual survey by\napplying at least one approved test loading condition (other than light ship). If a surveyor is not present for the computer check,\na copy of the test conditions results obtained by the computer check is to be retained on board as documentation of satisfactory\ntesting for the surveyor’s verification. At each renewal survey this checking for all approved test loading conditions is to be done\nin the presence of the Society surveyor.\n(Computer Software for On-board Stability Calculations-IACS Unified Interpretations, 2017)\nRegular on-board testing should also take place and records attesting to this should be maintained.\nWhen a vessel has undergone any weight variations, such as the installation of a scrubber, a ballast water treatment plant, or\nmajor structural modifications, it is the responsibility of the vessel’s manager to ensure that the loading instrument and stability\nbooklet are updated as necessary.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.7","internal_question_no":"08A.007","question_sort_key":8100700.203,"question_text":"Are the stresses, stability information and any limitations included in the cargo plan understood by the cargo watch officers, and are conditions being monitored and maintained within design limits throughout the cargo operation?","guide_to_inspection":"The officer in charge should closely monitor the ship’s condition during cargo operations. If a significant deviation from the agreed\nloading/unloading plan is detected, all cargo and ballast operations must STOP .\nThe officer in charge should ensure that:\n> The cargo operation and intended ballast/de-ballast procedure are synchronised\n> Draught surveys are conducted at appropriate steps of the loading/discharge plan to verify the ship’s condition\n> The draught readings, usually taken at amidships and the fore and aft perpendiculars, should be in good agreement with\nvalues calculated in the loading/discharging plan\n> Ballast tanks are sounded to verify their contents and rate of ballasting/de-ballasting\n> The cargo load is in agreement with the figures provided by the terminal\n> The SWSF, SWBM and, where appropriate, hold cargo weight versus draught calculations are performed at intermediate\nstages of the cargo operation. These results should be logged.\n> Any revised loading/unloading plan should be signed by a terminal representative and by the Master or Chief Officer.\nInspectors should make sure that regular monitoring of stress and stability have been taking place throughout cargo operation and\nverify if the vessel’s conditions have been maintained within design limits.\nThere are three main problems associated with high loading rates which may result in over-stressing the ship’s structure, namely:\n> The SWSF and SWBM may exceed the allowable limit\n> Overloading the local structure.\n> Synchronization of the ballasting operations may not be maintained.\nHigh cargo loading rates may create problems with the ballasting operation as the pumping capacity of the ship may be relatively\nlow compared to the cargo loading rate. In such cases the cargo operation must be stopped to ensure synchronisation with the\nballasting operation is maintained.\nWhen necessary, the loading rate must be adjusted to synchronise with the ship’s pumping capacity.\n(Bulk Carg o Loading and Discharging Guidance, 2012)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":113,"source_page_end":113,"raw_source_text":"Are the stresses, stability information and any limitations included in the cargo plan understood by the\ncargo watch officers, and are conditions being monitored and maintained within design limits throughout\nthe cargo operation? (V)\nGuide to Inspection\nThe officer in charge should closely monitor the ship’s condition during cargo operations. If a significant deviation from the agreed\nloading/unloading plan is detected, all cargo and ballast operations must STOP .\nThe officer in charge should ensure that:\n> The cargo operation and intended ballast/de-ballast procedure are synchronised\n> Draught surveys are conducted at appropriate steps of the loading/discharge plan to verify the ship’s condition\n> The draught readings, usually taken at amidships and the fore and aft perpendiculars, should be in good agreement with\nvalues calculated in the loading/discharging plan\n> Ballast tanks are sounded to verify their contents and rate of ballasting/de-ballasting\n> The cargo load is in agreement with the figures provided by the terminal\n> The SWSF, SWBM and, where appropriate, hold cargo weight versus draught calculations are performed at intermediate\nstages of the cargo operation. These results should be logged.\n> Any revised loading/unloading plan should be signed by a terminal representative and by the Master or Chief Officer.\nInspectors should make sure that regular monitoring of stress and stability have been taking place throughout cargo operation and\nverify if the vessel’s conditions have been maintained within design limits.\nThere are three main problems associated with high loading rates which may result in over-stressing the ship’s structure, namely:\n> The SWSF and SWBM may exceed the allowable limit\n> Overloading the local structure.\n> Synchronization of the ballasting operations may not be maintained.\nHigh cargo loading rates may create problems with the ballasting operation as the pumping capacity of the ship may be relatively\nlow compared to the cargo loading rate. In such cases the cargo operation must be stopped to ensure synchronisation with the\nballasting operation is maintained.\nWhen necessary, the loading rate must be adjusted to synchronise with the ship’s pumping capacity.\n(Bulk Carg o Loading and Discharging Guidance, 2012)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.8","internal_question_no":"08A.008","question_sort_key":8100800.204,"question_text":"Are there procedures in place for loading, ballasting and de-ballasting of the designated ballast holds?","guide_to_inspection":"When cargo is to be carried in the ballast hold:\n> Proper steps should be taken to ensure that ballast water cannot be admitted to the hold by accident\n> Blanks or cover plates which were fitted to the bilge, the CO2 smothering lines and to the hatch coaming drains must be\nremoved so that these systems can operate whilst cargo is being carried.\nBefore ballasting of ballast hold:\n> It is vital to remove any blanks or cover plates which have been fitted to ballast suctions within the hold\n> The bilge suctions should be sealed to prevent ballast from leaking through the bilge system\n> The CO injection and the coaming drains must be sealed\n2\n> Cargo residue and rubbish could block the ballast suction, so they must be removed from the hold.\nDe-ballasting:\n> Hatch Cover Vents open.\nHold vents must be open when ballasting and/or de-ballasting the designated ballast hold.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":113,"source_page_end":113,"raw_source_text":"Are there procedures in place for loading, ballasting and de-ballasting of the designated ballast holds? (V)\nGuide to Inspection\nWhen cargo is to be carried in the ballast hold:\n> Proper steps should be taken to ensure that ballast water cannot be admitted to the hold by accident\n> Blanks or cover plates which were fitted to the bilge, the CO2 smothering lines and to the hatch coaming drains must be\nremoved so that these systems can operate whilst cargo is being carried.\nBefore ballasting of ballast hold:\n> It is vital to remove any blanks or cover plates which have been fitted to ballast suctions within the hold\n> The bilge suctions should be sealed to prevent ballast from leaking through the bilge system\n> The CO injection and the coaming drains must be sealed\n2\n> Cargo residue and rubbish could block the ballast suction, so they must be removed from the hold.\nDe-ballasting:\n> Hatch Cover Vents open.\nHold vents must be open when ballasting and/or de-ballasting the designated ballast hold.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.9","internal_question_no":"08A.009","question_sort_key":8100900.205,"question_text":"Are there guidelines and procedures for hold cleaning after completion of unloading?","guide_to_inspection":"Record the list of hold cleaning equipment available on board in comments.\nBulk cargoes include a very wide range of commodities. The level of cleanliness required before loading and additional\npreparation will depend upon the type of cargo to be loaded. The vessel’s manager shall provide comprehensive hold cleaning\nguidelines, procedures, a hold cleaning matrix for change of cargo and a hold cleaning inspection checklist.\nCargo hold cleaning plans shall consist of the following steps, where applicable:\n1. Removal of dunnage, lashing material and / or cargo residues\n2. Holds swept down\n3. Holds swept down a second time (double swept)\n4. Cargo residues that have set hard removed\n5. Cleaning chemicals applied to hold surfaces and allowed to penetrate/react with stains prior to being washed off\n6. Holds washed down with sea water\n7. Holds washed down with detergents mixed in fresh water\n8. Holds rinsed with fresh water to remove all traces of chlorides and detergents\n9. Bilge wells and plates / strainers cleaned\n10. Holds air dried\n11. Loose paint flakes, loose rust scale and paint blisters removed\n12. Paintwork touched-up\n13. Barrier coat applied\nSome vessels are equipped with fixed cargo hold washing machines, however, these vessels are in a minority and most vessels\ncarrying solid bulk cargoes will need to manually wash the cargo holds. Where fixed washing machines are used, manual\ncleaning of shadow sectors within the holds may still be required.\n(Cargo Hold Cleaning, 2017)\nDuring the operation, the Master or Chief Officer should carry out inspections to ensure the cleaning is being carried out correctly\nand by use of the correct material and equipment. Inspections should be carried out at least once during each day by the Master\nor Chief Officer accompanied by the Bosun, to establish how the operation is progressing.\nThe cargo hold cleaning checklist should be incorporated in the vessel manager’s hold cleaning procedure.\nWhen end folding hatch cover panels are partially opened and not secured, they can place massive strains and back pressure on\nthe hatch cover’s hydraulic system, leading to failure of one or more hydraulic system components, such as hydraulic pipes, and\naccidental hatch cover closure. This unintentional closure may raise the risk of injury to those working near the hatch cover.\nThe hatch covers must be completely opened and secured in line with the manufacturer’s recommendations during cargo hold\ncleaning.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":114,"source_page_end":114,"raw_source_text":"Are there guidelines and procedures for hold cleaning after completion of unloading? (V)\nGuide to Inspection\nRecord the list of hold cleaning equipment available on board in comments.\nBulk cargoes include a very wide range of commodities. The level of cleanliness required before loading and additional\npreparation will depend upon the type of cargo to be loaded. The vessel’s manager shall provide comprehensive hold cleaning\nguidelines, procedures, a hold cleaning matrix for change of cargo and a hold cleaning inspection checklist.\nCargo hold cleaning plans shall consist of the following steps, where applicable:\n1. Removal of dunnage, lashing material and / or cargo residues\n2. Holds swept down\n3. Holds swept down a second time (double swept)\n4. Cargo residues that have set hard removed\n5. Cleaning chemicals applied to hold surfaces and allowed to penetrate/react with stains prior to being washed off\n6. Holds washed down with sea water\n7. Holds washed down with detergents mixed in fresh water\n8. Holds rinsed with fresh water to remove all traces of chlorides and detergents\n9. Bilge wells and plates / strainers cleaned\n10. Holds air dried\n11. Loose paint flakes, loose rust scale and paint blisters removed\n12. Paintwork touched-up\n13. Barrier coat applied\nSome vessels are equipped with fixed cargo hold washing machines, however, these vessels are in a minority and most vessels\ncarrying solid bulk cargoes will need to manually wash the cargo holds. Where fixed washing machines are used, manual\ncleaning of shadow sectors within the holds may still be required.\n(Cargo Hold Cleaning, 2017)\nDuring the operation, the Master or Chief Officer should carry out inspections to ensure the cleaning is being carried out correctly\nand by use of the correct material and equipment. Inspections should be carried out at least once during each day by the Master\nor Chief Officer accompanied by the Bosun, to establish how the operation is progressing.\nThe cargo hold cleaning checklist should be incorporated in the vessel manager’s hold cleaning procedure.\nWhen end folding hatch cover panels are partially opened and not secured, they can place massive strains and back pressure on\nthe hatch cover’s hydraulic system, leading to failure of one or more hydraulic system components, such as hydraulic pipes, and\naccidental hatch cover closure. This unintentional closure may raise the risk of injury to those working near the hatch cover.\nThe hatch covers must be completely opened and secured in line with the manufacturer’s recommendations during cargo hold\ncleaning.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.10","internal_question_no":"08A.010","question_sort_key":8101000.206,"question_text":"Is the vessel free of any limitations or restrictions specified in the Loading Manual or Trim and Stability Booklet?","guide_to_inspection":"The ship shall be provided with an approved stability and loading booklet written in a language understood by the ship’s officers.\n(The Code of Practice for the Safe Loading and Unloading of Bulk Carriers, 2011)\nImportant restrictions should be recorded in the inspector comments section.\nBulk carriers of 150 m in length and upwards of single-side skin construction, carrying cargoes having a density of 1,780 kg/\nm³ and above, if not meeting the requirements for withstanding flooding of any one cargo hold as specified in regulation 5.1\nand the standards and criteria for side structures of bulk carriers of single-side skin construction, adopted by the Organization\nby resolution MSC.168(79), shall not sail with any hold loaded to less than 10% of the hold’s maximum allowable cargo weight\nwhen in the full load condition, after reaching 10 years of age. The applicable full load condition for this regulation is a load equal\nto or greater than 90% of the ship’s deadweight at the relevant assigned freeboard.\n(SOLAS 74, 2020)\nStrength of the inner bottom plating could be deteriorated due to corrosion wastage. The operational parameters and tank top\nstrength(T/m2) of the effected vessels may be updated by the classification society.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":114,"source_page_end":114,"raw_source_text":"Is the vessel free of any limitations or restrictions specified in the Loading Manual or Trim and\nStability Booklet? (V)\nGuide to Inspection\nThe ship shall be provided with an approved stability and loading booklet written in a language understood by the ship’s officers.\n(The Code of Practice for the Safe Loading and Unloading of Bulk Carriers, 2011)\nImportant restrictions should be recorded in the inspector comments section.\nBulk carriers of 150 m in length and upwards of single-side skin construction, carrying cargoes having a density of 1,780 kg/\nm³ and above, if not meeting the requirements for withstanding flooding of any one cargo hold as specified in regulation 5.1\nand the standards and criteria for side structures of bulk carriers of single-side skin construction, adopted by the Organization\nby resolution MSC.168(79), shall not sail with any hold loaded to less than 10% of the hold’s maximum allowable cargo weight\nwhen in the full load condition, after reaching 10 years of age. The applicable full load condition for this regulation is a load equal\nto or greater than 90% of the ship’s deadweight at the relevant assigned freeboard.\n(SOLAS 74, 2020)\nStrength of the inner bottom plating could be deteriorated due to corrosion wastage. The operational parameters and tank top\nstrength(T/m2) of the effected vessels may be updated by the classification society.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.11","internal_question_no":"08A.011","question_sort_key":8101100.207,"question_text":"Are officers familiar with the risk, hazard and carriage requirements of solid bulk cargo on board the ship?","guide_to_inspection":"The IMSBC Code categorises cargoes into three groups:\n> Group A - cargoes which may liquefy if shipped at a moisture content exceeding their Transportable Moisture Limit (TML).\n> Group B – cargoes which possess a chemical hazard which could give rise to a dangerous situation on a ship.\n> Group C – cargoes which are neither liable to liquefy (Group A) nor possess chemical hazards (Group B). Cargoes in this\ngroup can still be hazardous.\nCargo-carrying can involve serious risk, which must be managed carefully to safeguard the crew and the ship. These risks\ninclude but are not limited to reduced ship stability and even capsizing due to cargo liquefaction, fire or explosion due to\nchemical hazards, and damage to ship structures due to poor loading procedures.\nOfficers shall be able to demonstrate a basic knowledge of the following:\n> Shipboard operations and cargo handling\n> MARPOL ANNEX V The discharge of wash water and any non-recoverable cargo residues\n> The IMSBC Code and BLU Codes\n> Cargo familiarity, i.e., hazard, stowage and segregation, hold cleanliness, weather precautions, ventilation, carriage,\ndischarge and clean up requirements.\n> Sampling and testing of the moisture content for solid bulk cargo, where applicable and, as required:\n> Precautions for cargoes which may liquefy.\n> Precautions for cargoes with chemical hazards.\n> Limitations when loading high density cargoes.\n> Precautions when loading/unloading corrosive cargoes.\n> Hazards associated with solid cargo that give off toxic gas.\n> Handling high density cargoes\n> Can Test\nA ship’s Master may carry out a check test for approximately determining the possibility of flow on board the ship or at the\ndockside by the following auxiliary method:\nHalf fill a cylindrical can or similar container (0.5 to 1 litre capacity) with a sample of the material. Take the can in one hand and\nbring it down sharply to strike a hard surface, such as a solid table, from a height of about 0.2 m. Repeat the procedure 25 times\nat one- or two-second intervals. Examine the surface for free moisture or fluid conditions. If free moisture or a fluid condition\nappears, arrangements should be made to have additional laboratory tests conducted on the material before it is accepted for\nloading.\nIf samples remain dry following a can test, the moisture content of the material may still exceed the Transportable Moisture\nLimit (TML).\n(IMSBC code, 2020)\nCan test is a simple and useful check available to the ship’s crew. When performed correctly, it can help determine if a cargo\nmight be unsafe.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":115,"source_page_end":115,"raw_source_text":"Are officers familiar with the risk, hazard and carriage requirements of solid bulk cargo on board the ship? (V)\nGuide to Inspection\nThe IMSBC Code categorises cargoes into three groups:\n> Group A - cargoes which may liquefy if shipped at a moisture content exceeding their Transportable Moisture Limit (TML).\n> Group B – cargoes which possess a chemical hazard which could give rise to a dangerous situation on a ship.\n> Group C – cargoes which are neither liable to liquefy (Group A) nor possess chemical hazards (Group B). Cargoes in this\ngroup can still be hazardous.\nCargo-carrying can involve serious risk, which must be managed carefully to safeguard the crew and the ship. These risks\ninclude but are not limited to reduced ship stability and even capsizing due to cargo liquefaction, fire or explosion due to\nchemical hazards, and damage to ship structures due to poor loading procedures.\nOfficers shall be able to demonstrate a basic knowledge of the following:\n> Shipboard operations and cargo handling\n> MARPOL ANNEX V The discharge of wash water and any non-recoverable cargo residues\n> The IMSBC Code and BLU Codes\n> Cargo familiarity, i.e., hazard, stowage and segregation, hold cleanliness, weather precautions, ventilation, carriage,\ndischarge and clean up requirements.\n> Sampling and testing of the moisture content for solid bulk cargo, where applicable and, as required:\n> Precautions for cargoes which may liquefy.\n> Precautions for cargoes with chemical hazards.\n> Limitations when loading high density cargoes.\n> Precautions when loading/unloading corrosive cargoes.\n> Hazards associated with solid cargo that give off toxic gas.\n> Handling high density cargoes\n> Can Test\nA ship’s Master may carry out a check test for approximately determining the possibility of flow on board the ship or at the\ndockside by the following auxiliary method:\nHalf fill a cylindrical can or similar container (0.5 to 1 litre capacity) with a sample of the material. Take the can in one hand and\nbring it down sharply to strike a hard surface, such as a solid table, from a height of about 0.2 m. Repeat the procedure 25 times\nat one- or two-second intervals. Examine the surface for free moisture or fluid conditions. If free moisture or a fluid condition\nappears, arrangements should be made to have additional laboratory tests conducted on the material before it is accepted for\nloading.\nIf samples remain dry following a can test, the moisture content of the material may still exceed the Transportable Moisture\nLimit (TML).\n(IMSBC code, 2020)\nCan test is a simple and useful check available to the ship’s crew. When performed correctly, it can help determine if a cargo\nmight be unsafe.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.12","internal_question_no":"08A.012","question_sort_key":8101200.208,"question_text":"Have precautionary measures to minimise the risk of potential liquefaction and chemical reaction within the cargo during the voyage been incorporated in the procedures, and are these procedures being followed?","guide_to_inspection":"During the voyage, the Master and crew should continue to monitor the state of the cargo as per the vessel’s manager’s\nprocedures and IMSBC Code, even if they are satisfied about the condition of the cargo they loaded.\nMechanical ventilation is to be provided for cargoes liable to emit flammable gases or vapours in an amount which can form an\nexplosive atmosphere with air.\n(IMSBC Code subsections 3.5.1 and 9.3.2.1.3).\nFor some cargoes like FERROSILICON 14082 or ALUMINIUM SILICON POWDER, UNCOATED 1398, the mechanical ventilation\nsystem must have a capacity of at least six air changes per hour based on an empty cargo space for removal of gases and\nvapours from cargo holds.\n(SOLAS Regulation II-2/19.3.4.1 and the IMSBC Code Appendix\n1. For the removal of gases and vapours, exhaust ventilation is recommended.\n2. For other cargoes, a specific capacity is not clearly defined. In this case, the ventilation should be adequate to avoid the build-\nup of a flammable atmosphere.3\n3. For cargoes with self-heating properties, mechanical ventilation should only be applied in special circumstances. In no case\nshall the ventilation be directed into the body of the cargo\n(IMSBC Code subsection 3.5.6 and Appendix 1).\nContinuous ventilation is required for cargoes that fall under IMDG Class 4.3 and are substances which, in contact with water,\nemit flammable gases, such as hydrogen gas, falling within the UN N.5 test as Dangerous Goods. In addition to Class 4.3\ncargoes, there are cargoes assigned MHB (WF) such as ‘FERROPHOSPHORUS (including briquettes)’ and ‘FERROSILICON with\nat least 25% but less than 30% silicon, or 90% or more silicon’ that also require continuous ventilation. IMSBC references to\ncontinuous ventilation requirements can be found within IMSBC Code subsections 3.5.3 and 3.5.4.\n(CARGO AND CARGO HOLD VENTILATION, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":115,"source_page_end":116,"raw_source_text":"Have precautionary measures to minimise the risk of potential liquefaction and chemical reaction\nwithin the cargo during the voyage been incorporated in the procedures, and are these\nprocedures being followed? (V)\nGuide to Inspection\nDuring the voyage, the Master and crew should continue to monitor the state of the cargo as per the vessel’s manager’s\nprocedures and IMSBC Code, even if they are satisfied about the condition of the cargo they loaded.\nMechanical ventilation is to be provided for cargoes liable to emit flammable gases or vapours in an amount which can form an\nexplosive atmosphere with air.\n(IMSBC Code subsections 3.5.1 and 9.3.2.1.3).\nFor some cargoes like FERROSILICON 14082 or ALUMINIUM SILICON POWDER, UNCOATED 1398, the mechanical ventilation\nsystem must have a capacity of at least six air changes per hour based on an empty cargo space for removal of gases and\nvapours from cargo holds.\n(SOLAS Regulation II-2/19.3.4.1 and the IMSBC Code Appendix\n1. For the removal of gases and vapours, exhaust ventilation is recommended.\n2. For other cargoes, a specific capacity is not clearly defined. In this case, the ventilation should be adequate to avoid the build-\nup of a flammable atmosphere.3\n3. For cargoes with self-heating properties, mechanical ventilation should only be applied in special circumstances. In no case\nshall the ventilation be directed into the body of the cargo\n(IMSBC Code subsection 3.5.6 and Appendix 1).\nContinuous ventilation is required for cargoes that fall under IMDG Class 4.3 and are substances which, in contact with water,\nemit flammable gases, such as hydrogen gas, falling within the UN N.5 test as Dangerous Goods. In addition to Class 4.3\ncargoes, there are cargoes assigned MHB (WF) such as ‘FERROPHOSPHORUS (including briquettes)’ and ‘FERROSILICON with\nat least 25% but less than 30% silicon, or 90% or more silicon’ that also require continuous ventilation. IMSBC references to\ncontinuous ventilation requirements can be found within IMSBC Code subsections 3.5.3 and 3.5.4.\n(CARGO AND CARGO HOLD VENTILATION, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.13","internal_question_no":"08A.013","question_sort_key":8101300.209,"question_text":"If the solid bulk cargo is not listed in the IMSBC Code, has the Master been provided with a certificate from the shipper, endorsed by the competent authority of the port, stating the characteristics of the cargo and the required conditions for carriage and handling?","guide_to_inspection":"If a solid cargo which is not listed in appendix 1 of the IMSBC Code is proposed for carriage in bulk, the shipper shall, prior to\nloading, provide the competent authority of the port of loading with the characteristics and properties of the cargo in accordance\nwith section 4 of the IMSBC Code. Based on the information received, the competent authority shall assess the acceptability of\nthe cargo for safe shipment.\nWhen it is assessed that the solid bulk cargo proposed for carriage may present hazards, such as those defined by group A or B\nof the IMSBC Code as defined in 1.7 of the code, advice is to be sought from the competent authorities of the port of unloading\nand of the Flag State. The three competent authorities will set the preliminary suitable conditions for the carriage of this cargo.\nWhen it is assessed that the solid bulk cargo proposed for carriage presents no specific hazards for transportation, the carriage\nof this cargo shall be authorised. The competent authorities of the port of unloading and of the Flag State shall be advised of\nthat authorisation.\nThe competent authority of the port of loading shall provide to the Master a certificate stating the characteristics of the cargo\nand the required conditions for carriage and handling of this shipment. The competent authority of the port of loading shall also\nsubmit an application to the Organization, within one year from the issue of the certificate, to incorporate this solid bulk cargo\ninto appendix 1 of the IMSBC Code.\nCompetent Authority means any national regulatory body or authority designated or otherwise recognized as such for any\npurpose in connection with the IMSBC Code. The competent authority shall operate independently from the shipper.\n(IMSBC code, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":116,"source_page_end":116,"raw_source_text":"If the solid bulk cargo is not listed in the IMSBC Code, has the Master been provided with a certificate\nfrom the shipper, endorsed by the competent authority of the port, stating the characteristics of the\ncargo and the required conditions for carriage and handling? (V)\nGuide to Inspection\nIf a solid cargo which is not listed in appendix 1 of the IMSBC Code is proposed for carriage in bulk, the shipper shall, prior to\nloading, provide the competent authority of the port of loading with the characteristics and properties of the cargo in accordance\nwith section 4 of the IMSBC Code. Based on the information received, the competent authority shall assess the acceptability of\nthe cargo for safe shipment.\nWhen it is assessed that the solid bulk cargo proposed for carriage may present hazards, such as those defined by group A or B\nof the IMSBC Code as defined in 1.7 of the code, advice is to be sought from the competent authorities of the port of unloading\nand of the Flag State. The three competent authorities will set the preliminary suitable conditions for the carriage of this cargo.\nWhen it is assessed that the solid bulk cargo proposed for carriage presents no specific hazards for transportation, the carriage\nof this cargo shall be authorised. The competent authorities of the port of unloading and of the Flag State shall be advised of\nthat authorisation.\nThe competent authority of the port of loading shall provide to the Master a certificate stating the characteristics of the cargo\nand the required conditions for carriage and handling of this shipment. The competent authority of the port of loading shall also\nsubmit an application to the Organization, within one year from the issue of the certificate, to incorporate this solid bulk cargo\ninto appendix 1 of the IMSBC Code.\nCompetent Authority means any national regulatory body or authority designated or otherwise recognized as such for any\npurpose in connection with the IMSBC Code. The competent authority shall operate independently from the shipper.\n(IMSBC code, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.14","internal_question_no":"08A.014","question_sort_key":8101400.21,"question_text":"Has as a cargo loading/unloading plan providing a detailed sequence of cargo and ballast transfer been prepared, understood, and signed off by the Master and deck officers?","guide_to_inspection":"General requirements\nA cargo loading/unloading plan should be laid out in such a way that for each step of the cargo operation there is a clear\nindication of:\n> The quantity of cargo and the corresponding hold number(s) to be loaded/unloaded.\n> The amount of water ballast and the corresponding tank/hold number(s) to be discharged/loaded.\n> The ship’s draughts and trim at the completion of each step in the cargo operation.\n> The calculated value of the still-water shear forces and bending moments at the completion of each step in the cargo\noperation.\n> Estimated time for completion of each step in the cargo operation.\n> Assumed rate(s) of loading and unloading equipment.\n> Assumed ballasting rate(s)\nThe loading/unloading plan should indicate any allowances for cargo stoppage (which may be necessary to allow the ship to\nde-ballast when the loading rate is high), shifting ship, bunkering, draught checks, and cargo trimming.\n(Bulk Cargo Loading and Discharging Guidance, 2012)\nLoading plan consideration:\n> The arrangements at the port including the number of loaders and their range of movement, the least depth alongside and\nthe air draft requirements\n> The loading sequence, including the number of pours per hold, where loading should begin and where the final trimming\npours should be loaded\n> De-ballasting, including the timing of that operation, to coincide with the loading sequence, and the need for a substantial\ntrim during stripping of the ballast tanks\n> The shear force, bending moments and stability of the ship at all stages of the operation, and\n> Trimming pours and the final draft requirements.\nUnloading plan consideration:\n> The port arrangements, including the number of unloaders available and their range of movement, the maximum draft\navailable and the minimum draft available\n> The weight of cargo to be unloaded at the port or ports and its distribution on board\n> Ballasting including the timing of that ballasting operation which should coincide with the unloading sequence and trim of\nthe ship\n> The shear force, bending moments and stability of the ship at all stages of the operation, and\n> Final draft requirements and air draft requirements.\n(Bulk Cargoes: A Guide to Good Practice, 2016)\nThe cargo loading/unloading plan should be completed by the responsible officer prior to arrival at port and the commencement\nof cargo operations and verified and approved by the Master.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":116,"source_page_end":117,"raw_source_text":"Has as a cargo loading/unloading plan providing a detailed sequence of cargo and ballast transfer\nbeen prepared, understood, and signed off by the Master and deck officers? (V)\nGuide to Inspection\nGeneral requirements\nA cargo loading/unloading plan should be laid out in such a way that for each step of the cargo operation there is a clear\nindication of:\n> The quantity of cargo and the corresponding hold number(s) to be loaded/unloaded.\n> The amount of water ballast and the corresponding tank/hold number(s) to be discharged/loaded.\n> The ship’s draughts and trim at the completion of each step in the cargo operation.\n> The calculated value of the still-water shear forces and bending moments at the completion of each step in the cargo\noperation.\n> Estimated time for completion of each step in the cargo operation.\n> Assumed rate(s) of loading and unloading equipment.\n> Assumed ballasting rate(s)\nThe loading/unloading plan should indicate any allowances for cargo stoppage (which may be necessary to allow the ship to\nde-ballast when the loading rate is high), shifting ship, bunkering, draught checks, and cargo trimming.\n(Bulk Cargo Loading and Discharging Guidance, 2012)\nLoading plan consideration:\n> The arrangements at the port including the number of loaders and their range of movement, the least depth alongside and\nthe air draft requirements\n> The loading sequence, including the number of pours per hold, where loading should begin and where the final trimming\npours should be loaded\n> De-ballasting, including the timing of that operation, to coincide with the loading sequence, and the need for a substantial\ntrim during stripping of the ballast tanks\n> The shear force, bending moments and stability of the ship at all stages of the operation, and\n> Trimming pours and the final draft requirements.\nUnloading plan consideration:\n> The port arrangements, including the number of unloaders available and their range of movement, the maximum draft\navailable and the minimum draft available\n> The weight of cargo to be unloaded at the port or ports and its distribution on board\n> Ballasting including the timing of that ballasting operation which should coincide with the unloading sequence and trim of\nthe ship\n> The shear force, bending moments and stability of the ship at all stages of the operation, and\n> Final draft requirements and air draft requirements.\n(Bulk Cargoes: A Guide to Good Practice, 2016)\nThe cargo loading/unloading plan should be completed by the responsible officer prior to arrival at port and the commencement\nof cargo operations and verified and approved by the Master.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.15","internal_question_no":"08A.015","question_sort_key":8101500.211,"question_text":"Is an adequate record of all cargo operation activities maintained during loading and unloading?","guide_to_inspection":"The followings should be recorded in the port logbook or deck log book:\n> Starting and stopping of work at each hold; times and dates\n> Tonnages loaded per pour into each hold, and a running total loaded; and in the case of unloading, tonnages offloaded per\nshift from each hold and a running total offloaded.\n> Weather conditions at intervals – for example, 6 hours\n> Use of ship’s cranes, if appropriate\n> Movement of shore cranes, loaders or floating crane alongside\n> Movement of barges alongside, and of floating cranes or loaders if ship is at anchor\n> Opening and closing of hatches\n> Periods of precipitation\n> Draft readings\n> Any delays caused on board\n> Any surveyors attending or boarding with reason for attendance\n> Any stevedore’s damage to ship’s structure and/or fittings, and\n> Cargo temperature – in particular for seed cake and coal.\nThe values of SF and BM should be calculated at least at the end of each pour during cargo operation.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":117,"source_page_end":117,"raw_source_text":"Is an adequate record of all cargo operation activities maintained during loading and unloading? (V)\nGuide to Inspection\nThe followings should be recorded in the port logbook or deck log book:\n> Starting and stopping of work at each hold; times and dates\n> Tonnages loaded per pour into each hold, and a running total loaded; and in the case of unloading, tonnages offloaded per\nshift from each hold and a running total offloaded.\n> Weather conditions at intervals – for example, 6 hours\n> Use of ship’s cranes, if appropriate\n> Movement of shore cranes, loaders or floating crane alongside\n> Movement of barges alongside, and of floating cranes or loaders if ship is at anchor\n> Opening and closing of hatches\n> Periods of precipitation\n> Draft readings\n> Any delays caused on board\n> Any surveyors attending or boarding with reason for attendance\n> Any stevedore’s damage to ship’s structure and/or fittings, and\n> Cargo temperature – in particular for seed cake and coal.\nThe values of SF and BM should be calculated at least at the end of each pour during cargo operation.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.16","internal_question_no":"08A.016","question_sort_key":8101600.212,"question_text":"Have details of cargo care during the voyage been adequately recorded?","guide_to_inspection":"Where applicable, the following shall be recorded:\n> Records of ventilation on each day for each hold\n> All temperatures taken and dew points calculated\n> Whether or not ventilation has been carried out\n> Reason for not ventilating\n> Weather and sea conditions\n> Ventilation rule applied (e.g., three- degree rule or dew point rule)\nRecords relating to monitoring of cargo or hold atmosphere for each day (e.g., for coal or silicomanganese):\n> Result of measuring methane, oxygen, carbon monoxide and pH value; where applicable taken at each hold, with time\nreading taken\n> Any action necessary because of readings obtained, and the results of action taken\n> Findings during inspections of cargo in each hold, with time inspections carried out\n> Any action necessary because of findings, and the results of action taken\nRecords of bilge soundings and pumping operations:\n> Bilge sounding record\n> Time and dates of bilge pumping\n> Amount of water pumped out of each bilge well during each pumping\n> Sounding before and after each pumping\nRegular hold bilge testing shall be systematically carried out during voyages carrying coal cargo. If the pH monitoring indicates\nthat a corrosion risk exists, bilges shall be frequently pumped out during the voyage in order to avoid the possible accumulation\nof acids on tank tops and in the bilge system. Record of such monitoring should be available on board.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":117,"source_page_end":118,"raw_source_text":"Have details of cargo care during the voyage been adequately recorded? (V)\nGuide to Inspection\nWhere applicable, the following shall be recorded:\n> Records of ventilation on each day for each hold\n> All temperatures taken and dew points calculated\n> Whether or not ventilation has been carried out\n> Reason for not ventilating\n> Weather and sea conditions\n> Ventilation rule applied (e.g., three- degree rule or dew point rule)\nRecords relating to monitoring of cargo or hold atmosphere for each day (e.g., for coal or silicomanganese):\n> Result of measuring methane, oxygen, carbon monoxide and pH value; where applicable taken at each hold, with time\nreading taken\n> Any action necessary because of readings obtained, and the results of action taken\n> Findings during inspections of cargo in each hold, with time inspections carried out\n> Any action necessary because of findings, and the results of action taken\nRecords of bilge soundings and pumping operations:\n> Bilge sounding record\n> Time and dates of bilge pumping\n> Amount of water pumped out of each bilge well during each pumping\n> Sounding before and after each pumping\nRegular hold bilge testing shall be systematically carried out during voyages carrying coal cargo. If the pH monitoring indicates\nthat a corrosion risk exists, bilges shall be frequently pumped out during the voyage in order to avoid the possible accumulation\nof acids on tank tops and in the bilge system. Record of such monitoring should be available on board.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.17","internal_question_no":"08A.017","question_sort_key":8101700.213,"question_text":"Are the dangers associated with oxygen depletion of cargo understood by officers and crew, and have reasonable precautions been taken during routine inspections of the cargo, when entering the holds and adjacent spaces?","guide_to_inspection":"Some solid bulk cargoes are susceptible to oxidation, which may result in oxygen depletion, emission of toxic gases or fumes\nand self-heating. Some cargoes are not liable to oxidize but may emit toxic fumes, particularly when wet. There are also cargoes\nwhich, when wetted, are corrosive to skin, eyes and mucous membranes or to the ship’s structure. When these cargoes are\ncarried particular attention shall be paid to protection of personnel and the need for special precautions to be taken prior to\nloading and after unloading. Many solid bulk cargoes are liable to cause oxygen depletion in a cargo space or tank.\nThese include, but are not limited to, most vegetable products and forest products, ferrous metals, metal sulphide concentrates\nand coal cargoes. Emergency entry into a cargo space shall be undertaken only by trained personnel wearing self-contained\nbreathing apparatus and protective clothing, and always under the supervision of a responsible officer.\n(IMSBC code, 2020)\nBelow are examples of materials that can cause oxygen depletion:\n> Grain, grain products and residues from grain processing (such as bran, crushed grain, crushed malt, or meal), hops, malt\nhusks and spent malt\n> Oilseeds as well as products and residues from oilseeds (such as seed expellers, seed cake, oil cake and meal)\n> Copra\n> Wood in such forms as packaged timber, round wood logs, pulpwood, props (pit props and other prop wood), woodchips,\nwood shavings, wood pulp pellets and sawdust\n> Jute, hemp, flax, sisal, kapok, cotton and other vegetable fibres, empty bags, cotton waste, animal fibres, animal and\nvegetable fabric, wool waste, and rags\n> Fishmeal and fish scrap\n> Guano\n> Sulphatic ores and ore concentrate.\n> Charcoal, coal, and coal products\n> Direct reduced iron (DRI)\n> Dry ice\n> Metal wastes and chips, iron swarf, steel and other turnings, borings, drillings, shavings, filings, and cuttings; and scrap metal.\nVarious forms of Direct Reduced Iron (DRI) are detailed in the International Maritime Solid Bulk Cargoes (IMSBC) Code. With the\n2025 amendment to the IMSBC Code, DRI (D) has been newly introduced.\nThe principal forms of DRI are Type A (hot-moulded briquettes) and Type B (pellets). Fines generated during manufacturing and\nhandling processes were conventionally shipped under DRI (C). However, the IMSBC Code stipulates that the moisture content\nof this cargo must not exceed 0.3%. Due to handling practices, such as outdoor storage and exposure to rain, the moisture\ncontent sometimes exceeds 0.3%. To transport such cargo, DRI (D) (by-product fines with a moisture content of at least 2%)\nwas introduced as the fourth DRI schedule.\nIn the IMSBC Code, DRI (D) is classified both as Group A, which is liable to liquefy, and Group B, as Materials Hazardous only in\nBulk (MHB). The primary hazard related to DRI (D) transport is the generation of flammable hydrogen gas in the upper space of\nthe cargo hold. The code focuses on the measurement and control of hydrogen gas concentration through surface ventilation.\nFor more detailed information, please click here. (Japan P&I Club, 2025).","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":118,"source_page_end":118,"raw_source_text":"Are the dangers associated with oxygen depletion of cargo understood by officers and crew, and have\nreasonable precautions been taken during routine inspections of the cargo, when entering the holds\nand adjacent spaces? (V)\nGuide to Inspection\nSome solid bulk cargoes are susceptible to oxidation, which may result in oxygen depletion, emission of toxic gases or fumes\nand self-heating. Some cargoes are not liable to oxidize but may emit toxic fumes, particularly when wet. There are also cargoes\nwhich, when wetted, are corrosive to skin, eyes and mucous membranes or to the ship’s structure. When these cargoes are\ncarried particular attention shall be paid to protection of personnel and the need for special precautions to be taken prior to\nloading and after unloading. Many solid bulk cargoes are liable to cause oxygen depletion in a cargo space or tank.\nThese include, but are not limited to, most vegetable products and forest products, ferrous metals, metal sulphide concentrates\nand coal cargoes. Emergency entry into a cargo space shall be undertaken only by trained personnel wearing self-contained\nbreathing apparatus and protective clothing, and always under the supervision of a responsible officer.\n(IMSBC code, 2020)\nBelow are examples of materials that can cause oxygen depletion:\n> Grain, grain products and residues from grain processing (such as bran, crushed grain, crushed malt, or meal), hops, malt\nhusks and spent malt\n> Oilseeds as well as products and residues from oilseeds (such as seed expellers, seed cake, oil cake and meal)\n> Copra\n> Wood in such forms as packaged timber, round wood logs, pulpwood, props (pit props and other prop wood), woodchips,\nwood shavings, wood pulp pellets and sawdust\n> Jute, hemp, flax, sisal, kapok, cotton and other vegetable fibres, empty bags, cotton waste, animal fibres, animal and\nvegetable fabric, wool waste, and rags\n> Fishmeal and fish scrap\n> Guano\n> Sulphatic ores and ore concentrate.\n> Charcoal, coal, and coal products\n> Direct reduced iron (DRI)\n> Dry ice\n> Metal wastes and chips, iron swarf, steel and other turnings, borings, drillings, shavings, filings, and cuttings; and scrap metal.\nVarious forms of Direct Reduced Iron (DRI) are detailed in the International Maritime Solid Bulk Cargoes (IMSBC) Code. With the\n2025 amendment to the IMSBC Code, DRI (D) has been newly introduced.\nThe principal forms of DRI are Type A (hot-moulded briquettes) and Type B (pellets). Fines generated during manufacturing and\nhandling processes were conventionally shipped under DRI (C). However, the IMSBC Code stipulates that the moisture content\nof this cargo must not exceed 0.3%. Due to handling practices, such as outdoor storage and exposure to rain, the moisture\ncontent sometimes exceeds 0.3%. To transport such cargo, DRI (D) (by-product fines with a moisture content of at least 2%)\nwas introduced as the fourth DRI schedule.\nIn the IMSBC Code, DRI (D) is classified both as Group A, which is liable to liquefy, and Group B, as Materials Hazardous only in\nBulk (MHB). The primary hazard related to DRI (D) transport is the generation of flammable hydrogen gas in the upper space of\nthe cargo hold. The code focuses on the measurement and control of hydrogen gas concentration through surface ventilation.\nFor more detailed information, please click here. (Japan P&I Club, 2025).","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.18","internal_question_no":"08A.018","question_sort_key":8101800.214,"question_text":"If coal is carried, is the ship equipped with adequate instruments for monitoring the temperature of the cargo, the atmosphere of the hold headspace, and the pH value of the cargo bilge, are the instruments maintained and in good working order?Are the atmosphere in the cargo hold, the temperature of the cargo, and the pH value of the cargo bilge sample measured, recorded, and monitored, with actions taken in case of self-heating or excessive gas concentration?","guide_to_inspection":"The inspector should examine the cargo logbook and verify that the necessary records have been kept. A finding should be\nrecorded where incomplete records exist and if no action is was taken where the methane (CH4) level\nreached or exceeded 20% of the Lower Explosive Limit (LEL), or if the carbon monoxide (CO) level surpassed 50 PPM.\nThe ship shall be suitably fitted and carry on-board appropriate instruments for measuring the followings without requiring entry\ninto the cargo space:\n> Concentration of methane in the atmosphere\n> Concentration of oxygen in the atmosphere\n> Concentration of carbon monoxide in the atmosphere\n> Temperature\n> pH value of cargo space bilge samples.\nThese instruments shall be regularly serviced and calibrated. Ship personnel shall be trained in the use of such instruments.\nIt is recommended that means be provided for measuring the temperature of the cargo in the range 0°C to 100°C to enable the\nmeasurement of temperature of the cargo while being loaded and during voyage without requiring entry into the cargo space.\n(IMSBC code, 2020)\nGlass thermometers, either mercury or alcohol filled, are too fragile and thus unsuitable for this purpose. “Pocket thermometers”,\nin which the glass thermometer is held within a metal casing usually for mounting in tanks or pipes, are also unsuitable since\nthe reaction time of the thermometer will be greatly increased due to the metal casing having to equilibrate with the temperature\nof the coal being measured. Infrared thermometers only measure the surface temperature. Probes can typically measure at\ndepths up to 1m below the surface.(Monitoring of Self-Heating Coal Cargoes Prior to Loading, 2014)\nTemperatures measured by lowering thermometers into sounding pipes may be useful in general terms but should not be relied\nupon to reflect any changes occurring in the bulk of the cargo, as temperature monitoring via sounding pipes will only detect\nheating coal in the immediate vicinity and will not provide information on the bulk of the cargo.\n(How to monitor coal cargoes from Indonesia, 2011)\nBecause coal self-heats as a result of carbon monoxide (CO) emissions, measuring gas concentrations is regarded to be a\nmore reliable technique to check for self-heating than measuring temperature. Before measuring gas concentration, the hold\nventilation should be turned off for around 4 hours. If CO levels are greater than 50 ppm (or have been rising steadily for three\ndays), the cargo may be self-heating; in this case, ventilation should be shut off and ventilation openings sealed.\n(Guidance on the carriage of coal 2021)\nAll temperature-measuring equipment should be regularly checked, serviced, and calibrated as recommended by the\nmanufacturer, and the vessel should carry a sufficient quantity of spare parts.\nIf CH4 is increasing and above 20% LEL, ventilation needs to be considered a priority to avoid explosion risks, which are more\nacute than self-heating. It is advisable to seek expert advice if the CH4 level is increasing and close to or above 20% LEL.\nIf gas measurements indicate that CO is rising above 50 ppm in unventilated holds, this suggests that the coal has a tendency to\nself-heat. Expert advice is recommended if the CO level exceeds 50 ppm, as indicated in the IMSBC Code.\nIn such cases, gas measurements should be taken at least every 12 hours until the situation stabilises. (Coal cargoes: Avoiding\nexplosion and self-heating 2023)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":119,"source_page_end":119,"raw_source_text":"If coal is carried, is the ship equipped with adequate instruments for monitoring the temperature of the cargo,\nthe atmosphere of the hold headspace, and the pH value of the cargo bilge, are the instruments maintained\nand in good working order?Are the atmosphere in the cargo hold, the temperature of the cargo, and the pH\nvalue of the cargo bilge sample measured, recorded, and monitored, with actions taken in case of self-heating\nor excessive gas concentration? (V)\nGuide to Inspection\nThe inspector should examine the cargo logbook and verify that the necessary records have been kept. A finding should be\nrecorded where incomplete records exist and if no action is was taken where the methane (CH4) level\nreached or exceeded 20% of the Lower Explosive Limit (LEL), or if the carbon monoxide (CO) level surpassed 50 PPM.\nThe ship shall be suitably fitted and carry on-board appropriate instruments for measuring the followings without requiring entry\ninto the cargo space:\n> Concentration of methane in the atmosphere\n> Concentration of oxygen in the atmosphere\n> Concentration of carbon monoxide in the atmosphere\n> Temperature\n> pH value of cargo space bilge samples.\nThese instruments shall be regularly serviced and calibrated. Ship personnel shall be trained in the use of such instruments.\nIt is recommended that means be provided for measuring the temperature of the cargo in the range 0°C to 100°C to enable the\nmeasurement of temperature of the cargo while being loaded and during voyage without requiring entry into the cargo space.\n(IMSBC code, 2020)\nGlass thermometers, either mercury or alcohol filled, are too fragile and thus unsuitable for this purpose. “Pocket thermometers”,\nin which the glass thermometer is held within a metal casing usually for mounting in tanks or pipes, are also unsuitable since\nthe reaction time of the thermometer will be greatly increased due to the metal casing having to equilibrate with the temperature\nof the coal being measured. Infrared thermometers only measure the surface temperature. Probes can typically measure at\ndepths up to 1m below the surface.(Monitoring of Self-Heating Coal Cargoes Prior to Loading, 2014)\nTemperatures measured by lowering thermometers into sounding pipes may be useful in general terms but should not be relied\nupon to reflect any changes occurring in the bulk of the cargo, as temperature monitoring via sounding pipes will only detect\nheating coal in the immediate vicinity and will not provide information on the bulk of the cargo.\n(How to monitor coal cargoes from Indonesia, 2011)\nBecause coal self-heats as a result of carbon monoxide (CO) emissions, measuring gas concentrations is regarded to be a\nmore reliable technique to check for self-heating than measuring temperature. Before measuring gas concentration, the hold\nventilation should be turned off for around 4 hours. If CO levels are greater than 50 ppm (or have been rising steadily for three\ndays), the cargo may be self-heating; in this case, ventilation should be shut off and ventilation openings sealed.\n(Guidance on the carriage of coal 2021)\nAll temperature-measuring equipment should be regularly checked, serviced, and calibrated as recommended by the\nmanufacturer, and the vessel should carry a sufficient quantity of spare parts.\nIf CH4 is increasing and above 20% LEL, ventilation needs to be considered a priority to avoid explosion risks, which are more\nacute than self-heating. It is advisable to seek expert advice if the CH4 level is increasing and close to or above 20% LEL.\nIf gas measurements indicate that CO is rising above 50 ppm in unventilated holds, this suggests that the coal has a tendency to\nself-heat. Expert advice is recommended if the CO level exceeds 50 ppm, as indicated in the IMSBC Code.\nIn such cases, gas measurements should be taken at least every 12 hours until the situation stabilises. (Coal cargoes: Avoiding\nexplosion and self-heating 2023)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08A","section_number":8,"section_letter":"A","section_title":"Cargo Operation- Solid Bulk Cargo other than Grain","printed_question_no":"8.19","internal_question_no":"08A.019","question_sort_key":8101900.215,"question_text":"Is any special emergency equipment required by IMSBC on board(as applicable) and in a state of readiness during the cargo operation?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":119,"source_page_end":119,"raw_source_text":"Is any special emergency equipment required by IMSBC on board(as applicable) and in a state of readiness\nduring the cargo operation? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.1","internal_question_no":"08B.001","question_sort_key":8200100.216,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":120,"source_page_end":120,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.2","internal_question_no":"08B.002","question_sort_key":8200200.217,"question_text":"Has appropriate information about the cargo and its characteristics been provided to the Master or Master’s representative prior to loading?","guide_to_inspection":"The IMSBC does not cover carriage of grain in bulk; this is covered by the International Grain Code. Form of cargo information\nis required to be issued by shippers to the Master or Master’s representative prior to loading. The cargo information should\ncontain relevant information on inherent quality, safety risks and precautions. These forms should be the Master’s initial point of\nreference in preparing to load the particular cargo. However, the Master should also refer to other accepted industry guidelines,\nsuch as Thomas’ Stowage to verify the information stated on the form. (Carriage of Bulk Grain Cargoes, 2015)\nGeneral Rule: Grain cargoes shipped with average moisture content in the region of 12 to 14% have a high risk of going mouldy\nduring the voyage. The risk increases significantly if average moisture content exceeds 14%.\nGrain cargoes with an average moisture content of 10% or below has a low risk of going mouldy during the voyage.\n(Carriage of Grain Cargoes, 2015)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":120,"source_page_end":120,"raw_source_text":"Has appropriate information about the cargo and its characteristics been provided to the Master or\nMaster’s representative prior to loading? (V & M)\nGuide to Inspection\nThe IMSBC does not cover carriage of grain in bulk; this is covered by the International Grain Code. Form of cargo information\nis required to be issued by shippers to the Master or Master’s representative prior to loading. The cargo information should\ncontain relevant information on inherent quality, safety risks and precautions. These forms should be the Master’s initial point of\nreference in preparing to load the particular cargo. However, the Master should also refer to other accepted industry guidelines,\nsuch as Thomas’ Stowage to verify the information stated on the form. (Carriage of Bulk Grain Cargoes, 2015)\nGeneral Rule: Grain cargoes shipped with average moisture content in the region of 12 to 14% have a high risk of going mouldy\nduring the voyage. The risk increases significantly if average moisture content exceeds 14%.\nGrain cargoes with an average moisture content of 10% or below has a low risk of going mouldy during the voyage.\n(Carriage of Grain Cargoes, 2015)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.3","internal_question_no":"08B.003","question_sort_key":8200300.218,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":120,"source_page_end":120,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.4","internal_question_no":"08B.004","question_sort_key":8200400.219,"question_text":"Is the approved document of authorisation and grain stability booklet (Grain Loading Manual) provided?","guide_to_inspection":"A document of authorisation shall be issued for every ship loaded in accordance with the regulations of the Grain Code either by\nthe Administration or an organization recognized by it or by a Contracting Government on behalf of the Administration. It shall be\naccepted as evidence that the ship is capable of complying with the requirements of these regulations.\nThe document shall accompany or be incorporated into the grain loading manual provided to enable the Master to meet the\nrequirements of A7 of the Code. The manual shall meet the requirements of A6.3. of the Code.\nThe intact stability characteristics of any ship carrying bulk grain shall be shown to meet, throughout the voyage, at least the\ncriteria described in section 7 and Part B of the Grain code.\n(International Code for the Safe Carriage of Grain in Bulk, 1991)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":120,"source_page_end":120,"raw_source_text":"Is the approved document of authorisation and grain stability booklet (Grain Loading Manual) provided? (M)\nGuide to Inspection\nA document of authorisation shall be issued for every ship loaded in accordance with the regulations of the Grain Code either by\nthe Administration or an organization recognized by it or by a Contracting Government on behalf of the Administration. It shall be\naccepted as evidence that the ship is capable of complying with the requirements of these regulations.\nThe document shall accompany or be incorporated into the grain loading manual provided to enable the Master to meet the\nrequirements of A7 of the Code. The manual shall meet the requirements of A6.3. of the Code.\nThe intact stability characteristics of any ship carrying bulk grain shall be shown to meet, throughout the voyage, at least the\ncriteria described in section 7 and Part B of the Grain code.\n(International Code for the Safe Carriage of Grain in Bulk, 1991)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.5","internal_question_no":"08B.005","question_sort_key":8200500.22,"question_text":"If the document of authorisation was not provided, can the Master demonstrate the compliance of the ship’s stability with the Grain Code?","guide_to_inspection":"A ship without a document of authorisation shall not load grain until the Master satisfies the Administration, or the Contracting\nGovernment of the port of loading on behalf of the Administration, that the ship will comply with the requirements of the\nInternational Grain Code in its proposed loaded condition.\n> The total weight of the bulk grain shall not exceed one third of the deadweight of the ship.\n> All filled compartments, trimmed, shall be fitted with centreline divisions extending, for the full length of such\ncompartments, downwards from the underside of the deck or hatch covers to a distance below the deck line of at least one\neighth of the maximum breadth of the compartment or 2.4 m, whichever is the greater, except that saucers constructed in\naccordance with Grain code may be accepted in lieu of a centreline division in and beneath a hatchway except in the case\nof linseed and other seeds having similar properties;\n> All hatches to filled compartments, trimmed, shall be closed and covers secured in place.\n> All free grain surfaces in partly filled cargo space shall be trimmed level and secured in accordance with grain code.\n> Throughout the voyage the metacentric height after correction for the free surface effects of liquids in tanks shall be 0.3 m\nor that given by the following formula, whichever is the greater:\nGMR = L B Vd (0.25 B – 0.645 × square root of Vd B)/ SF x Δ x 0.0875\nWhere:\nL = total combined length of all full compartments (metres)\nB = moulded breadth of the vessel (metres)\nSF = stowage factor (cubic metres per tonne)\nVd = calculated average void depth calculated in accordance with B 1 (metres-Note: not millimetres)\nΔ = displacement (tonnes)\nThe Master must demonstrate to the satisfaction of the Administration or the Contracting Government of the port of loading on\nbehalf of the Administration that the ship in its proposed loaded condition will comply with the requirements of this section.\n(International Code for the Safe Carriage of Grain in Bulk, 1991)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":121,"source_page_end":121,"raw_source_text":"If the document of authorisation was not provided, can the Master demonstrate the compliance of\nthe ship’s stability with the Grain Code? (V)\nGuide to Inspection\nA ship without a document of authorisation shall not load grain until the Master satisfies the Administration, or the Contracting\nGovernment of the port of loading on behalf of the Administration, that the ship will comply with the requirements of the\nInternational Grain Code in its proposed loaded condition.\n> The total weight of the bulk grain shall not exceed one third of the deadweight of the ship.\n> All filled compartments, trimmed, shall be fitted with centreline divisions extending, for the full length of such\ncompartments, downwards from the underside of the deck or hatch covers to a distance below the deck line of at least one\neighth of the maximum breadth of the compartment or 2.4 m, whichever is the greater, except that saucers constructed in\naccordance with Grain code may be accepted in lieu of a centreline division in and beneath a hatchway except in the case\nof linseed and other seeds having similar properties;\n> All hatches to filled compartments, trimmed, shall be closed and covers secured in place.\n> All free grain surfaces in partly filled cargo space shall be trimmed level and secured in accordance with grain code.\n> Throughout the voyage the metacentric height after correction for the free surface effects of liquids in tanks shall be 0.3 m\nor that given by the following formula, whichever is the greater:\nGMR = L B Vd (0.25 B – 0.645 × square root of Vd B)/ SF x Δ x 0.0875\nWhere:\nL = total combined length of all full compartments (metres)\nB = moulded breadth of the vessel (metres)\nSF = stowage factor (cubic metres per tonne)\nVd = calculated average void depth calculated in accordance with B 1 (metres-Note: not millimetres)\nΔ = displacement (tonnes)\nThe Master must demonstrate to the satisfaction of the Administration or the Contracting Government of the port of loading on\nbehalf of the Administration that the ship in its proposed loaded condition will comply with the requirements of this section.\n(International Code for the Safe Carriage of Grain in Bulk, 1991)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.6","internal_question_no":"08B.006","question_sort_key":8200600.221,"question_text":"Is a Class-approved loading computer or programme in use and has its operational accuracy been regularly tested?","guide_to_inspection":"The Grain Code specifies how to determine the grain shift moment, and it sets the stability criteria for ships carrying grain in\nbulk. The loading computer or program shall be able to:\n> Calculate grain shift moments.\n> Calculate the allowable grain heeling moments.\n> Determine whether a loading condition complies with the grain stability criteria.\n> Create the table needed for the loading manual.\nA loading instrument is an instrument, which is either analogue or digital, by means of which it can be easily and quickly\nascertained that, at specified read-out points, the still water bending moments, shear forces, and the still water torsional\nmoments and lateral loads, where applicable, in any load or ballast condition will not exceed the specified permissible values. A\nloading instrument comprises hardware and software.\n(SOLAS Requirement, regulation 11, Loading Instrument)\nBulk carriers of 150 m in length and upwards shall be fitted with a loading instrument capable of providing information on hull\ngirder shear forces and bending moments, taking into account the recommendations adopted by the Organization.\nBulk carriers of 150 m in length and upwards constructed before 1 July 1999 shall comply with the requirements not later than\nthe date of the first intermediate or periodical survey of the ship to be carried out after 1 July 1999.\nBulk carriers of less than 150 m in length constructed on or after 1 July 2006 shall be fitted with a loading instrument capable of\nproviding information on the ship’s stability in the intact condition.\nThe computer software shall be approved for stability calculations by the Administration and shall be provided with standard\nconditions for testing purposes relating to the approved stability information.\n(SOLAS 74,2020)\nIt is the responsibility of the ship’s Master to check the accuracy of the loading computer system at each annual survey by\napplying at least one approved test loading condition (other than light ship). If a surveyor is not present for the computer check,\na copy of the test conditions results obtained by the computer check is to be retained on board as documentation of satisfactory\ntesting for the surveyor’s verification. At each renewal survey this checking for all approved test loading conditions is to be done\nin the presence of the Society surveyor.\n(Computer Software for On-board Stability Calculations-IACS Unified Interpretations, 2017)\nRegular on-board testing should also take place and records attesting to this should be maintained.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":121,"source_page_end":121,"raw_source_text":"Is a Class-approved loading computer or programme in use and has its operational accuracy been\nregularly tested? (V)\nGuide to Inspection\nThe Grain Code specifies how to determine the grain shift moment, and it sets the stability criteria for ships carrying grain in\nbulk. The loading computer or program shall be able to:\n> Calculate grain shift moments.\n> Calculate the allowable grain heeling moments.\n> Determine whether a loading condition complies with the grain stability criteria.\n> Create the table needed for the loading manual.\nA loading instrument is an instrument, which is either analogue or digital, by means of which it can be easily and quickly\nascertained that, at specified read-out points, the still water bending moments, shear forces, and the still water torsional\nmoments and lateral loads, where applicable, in any load or ballast condition will not exceed the specified permissible values. A\nloading instrument comprises hardware and software.\n(SOLAS Requirement, regulation 11, Loading Instrument)\nBulk carriers of 150 m in length and upwards shall be fitted with a loading instrument capable of providing information on hull\ngirder shear forces and bending moments, taking into account the recommendations adopted by the Organization.\nBulk carriers of 150 m in length and upwards constructed before 1 July 1999 shall comply with the requirements not later than\nthe date of the first intermediate or periodical survey of the ship to be carried out after 1 July 1999.\nBulk carriers of less than 150 m in length constructed on or after 1 July 2006 shall be fitted with a loading instrument capable of\nproviding information on the ship’s stability in the intact condition.\nThe computer software shall be approved for stability calculations by the Administration and shall be provided with standard\nconditions for testing purposes relating to the approved stability information.\n(SOLAS 74,2020)\nIt is the responsibility of the ship’s Master to check the accuracy of the loading computer system at each annual survey by\napplying at least one approved test loading condition (other than light ship). If a surveyor is not present for the computer check,\na copy of the test conditions results obtained by the computer check is to be retained on board as documentation of satisfactory\ntesting for the surveyor’s verification. At each renewal survey this checking for all approved test loading conditions is to be done\nin the presence of the Society surveyor.\n(Computer Software for On-board Stability Calculations-IACS Unified Interpretations, 2017)\nRegular on-board testing should also take place and records attesting to this should be maintained.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}}]}$RISQQ71$::jsonb AS payload
),
qs AS (
  SELECT id AS question_set_id FROM public.risq_question_sets WHERE question_set_code = 'RISQ_3_2' LIMIT 1
),
input_rows AS (
  SELECT *
  FROM payload p
  CROSS JOIN LATERAL jsonb_to_recordset(p.payload->'questions') AS r(
    section_code text,
    section_number integer,
    section_letter text,
    section_title text,
    printed_question_no text,
    internal_question_no text,
    question_sort_key numeric,
    question_text text,
    guide_to_inspection text,
    answer_type text,
    answer_options jsonb,
    answer_options_inferred boolean,
    inspection_marker text,
    is_removed_question boolean,
    is_active boolean,
    guide_status text,
    source_page_start integer,
    source_page_end integer,
    raw_source_text text,
    metadata jsonb
  )
),
section_lookup AS (
  SELECT s.id AS section_id, s.question_set_id, s.section_code
  FROM public.risq_sections s
  JOIN qs ON qs.question_set_id = s.question_set_id
)
INSERT INTO public.risq_questions (
  question_set_id,
  section_id,
  section_code,
  section_number,
  section_letter,
  section_title,
  printed_question_no,
  internal_question_no,
  question_sort_key,
  question_text,
  guide_to_inspection,
  answer_type,
  answer_options,
  answer_options_inferred,
  inspection_marker,
  is_removed_question,
  is_active,
  guide_status,
  source_page_start,
  source_page_end,
  raw_source_text,
  source_hash,
  metadata,
  created_by,
  updated_by
)
SELECT
  qs.question_set_id,
  sl.section_id,
  i.section_code,
  i.section_number,
  i.section_letter,
  i.section_title,
  i.printed_question_no,
  i.internal_question_no,
  i.question_sort_key,
  i.question_text,
  i.guide_to_inspection,
  i.answer_type,
  i.answer_options,
  COALESCE(i.answer_options_inferred, false),
  COALESCE(i.inspection_marker, ''),
  COALESCE(i.is_removed_question, false),
  COALESCE(i.is_active, true),
  i.guide_status,
  i.source_page_start,
  i.source_page_end,
  i.raw_source_text,
  md5(COALESCE(i.question_text, '') || '|' || COALESCE(i.guide_to_inspection, '') || '|' || COALESCE(i.raw_source_text, '')),
  COALESCE(i.metadata, '{}'::jsonb),
  auth.uid(),
  auth.uid()
FROM input_rows i
CROSS JOIN qs
JOIN section_lookup sl
  ON sl.question_set_id = qs.question_set_id
 AND sl.section_code = i.section_code
ON CONFLICT (question_set_id, internal_question_no)
DO UPDATE SET
  section_id = EXCLUDED.section_id,
  section_code = EXCLUDED.section_code,
  section_number = EXCLUDED.section_number,
  section_letter = EXCLUDED.section_letter,
  section_title = EXCLUDED.section_title,
  printed_question_no = EXCLUDED.printed_question_no,
  question_sort_key = EXCLUDED.question_sort_key,
  question_text = EXCLUDED.question_text,
  guide_to_inspection = EXCLUDED.guide_to_inspection,
  answer_type = EXCLUDED.answer_type,
  answer_options = EXCLUDED.answer_options,
  answer_options_inferred = EXCLUDED.answer_options_inferred,
  inspection_marker = EXCLUDED.inspection_marker,
  is_removed_question = EXCLUDED.is_removed_question,
  is_active = EXCLUDED.is_active,
  guide_status = EXCLUDED.guide_status,
  source_page_start = EXCLUDED.source_page_start,
  source_page_end = EXCLUDED.source_page_end,
  raw_source_text = EXCLUDED.raw_source_text,
  source_hash = EXCLUDED.source_hash,
  metadata = EXCLUDED.metadata,
  updated_by = auth.uid();

COMMIT;

SELECT
  'RISQ question chunk 7/15 imported.' AS result,
  '07D.010' AS chunk_first_question,
  '08B.006' AS chunk_last_question,
  (SELECT COUNT(*) FROM public.risq_questions q JOIN public.risq_question_sets qs ON qs.id = q.question_set_id WHERE qs.question_set_code = 'RISQ_3_2') AS total_questions_imported_so_far;
